INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('ca83811c-8b03-43da-be7b-c3bd7b4d3102', 'pq-001', 'apprentice', 'theory', 'Theory', 'Which statement best explains why Voltage, Current, Resistance, and Ohm''s Law matters in daily electrical work?', '{"A":"It helps the electrician make a safer, code-based decision about understand voltage, current, resistance, apply ohm''s law, recognize safety implications.","B":"It replaces the need to read manufacturer instructions when equipment is listed.","C":"It only matters after the final inspection has already been completed.","D":"It applies only on large commercial projects and not on normal branch-circuit work."}'::jsonb, 'A', 'It helps the electrician make a safer, code-based decision about understand voltage, current, resistance, apply ohm''s law, recognize safety implications is strongest because Voltage, Current, Resistance, and Ohm''s Law matters before the final installation choice is made, not after it. The distractors are weaker because listed equipment still requires instructions, inspections do not erase code duties, and this topic is not limited to one project type.', 'Article 100', 'beginner', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('51f0a8bd-eaff-4f13-8d30-3d0f46ae1a14', 'pq-002', 'apprentice', 'theory', 'Theory', 'When a problem turns on Voltage, Current, Resistance, and Ohm''s Law, which NEC reference is the best place to start?', '{"A":"90.1","B":"Article 100","C":"110.3(B)","D":"110.4"}'::jsonb, 'B', 'Start with NEC Article 100 because it is the anchor reference attached to Voltage, Current, Resistance, and Ohm''s Law. The other options may appear nearby in study, but they are weaker because they do not control this lesson as directly as Article 100 does.', 'Article 100', 'intermediate', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('1cafbbbc-a098-4f0b-b903-685750d2db74', 'pq-003', 'apprentice', 'theory', 'Theory', 'Which field decision shows the best application of Voltage, Current, Resistance, and Ohm''s Law?', '{"A":"Using the first familiar answer choice without checking whether the condition in the problem changed the rule.","B":"Selecting the largest available equipment so code details no longer matter.","C":"Checking the actual condition, applying NEC Article 100, and then choosing the installation method or rating that matches that condition.","D":"Ignoring definitions and exceptions because the lesson title already sounds familiar."}'::jsonb, 'C', 'Checking the actual condition, applying NEC Article 100, and then choosing the installation method or rating that matches that condition is strongest because it follows the same order a competent electrician would use in the field. The distractors are weaker because they answer from familiarity, oversize equipment without support, or ignore definitions and exceptions that can change the result.', 'Article 100', 'intermediate', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('0a4ec15d-8d86-4505-8e7e-d8a8dd1f7e23', 'pq-004', 'apprentice', 'theory', 'Theory', 'Which mistake is most likely to produce a wrong answer about Voltage, Current, Resistance, and Ohm''s Law on an exam?', '{"A":"Writing the controlling code reference in the margin before comparing answer choices.","B":"Separating the given values from the unknown value before doing a calculation.","C":"Checking whether a special rule modifies a general requirement before finalizing the answer.","D":"Answering from memory before confirming the actual condition, definition, or table that controls the problem."}'::jsonb, 'D', 'The correct choice is strongest because exam writers often reward whoever confirms the condition, definition, or table first rather than whoever recognizes the lesson title fastest. The distractors describe good habits, but they are weaker because they do not identify the mistake most likely to create a wrong answer on this topic.', 'Article 100', 'intermediate', TRUE);
