INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('4daefeb2-46dc-4847-9430-b02d6b4d521a', 'pq-028', 'apprentice', 'safety', 'Safety', 'Which mistake is most likely to produce a wrong answer about Arc Flash and Protection on an exam?', '{"A":"Writing the controlling code reference in the margin before comparing answer choices.","B":"Answering from memory before confirming the actual condition, definition, or table that controls the problem.","C":"Separating the given values from the unknown value before doing a calculation.","D":"Checking whether a special rule modifies a general requirement before finalizing the answer."}'::jsonb, 'B', 'The correct choice is strongest because exam writers often reward whoever confirms the condition, definition, or table first rather than whoever recognizes the lesson title fastest. The distractors describe good habits, but they are weaker because they do not identify the mistake most likely to create a wrong answer on this topic.', '110.16', 'intermediate', TRUE);
