INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('0b24c2bd-f469-431d-b631-fecdd69b545a', 'pq-056', 'apprentice', 'installation', 'Installation', 'Which mistake is most likely to produce a wrong answer about Cable Types and Assemblies on an exam?', '{"A":"Answering from memory before confirming the actual condition, definition, or table that controls the problem.","B":"Writing the controlling code reference in the margin before comparing answer choices.","C":"Separating the given values from the unknown value before doing a calculation.","D":"Checking whether a special rule modifies a general requirement before finalizing the answer."}'::jsonb, 'A', 'The correct choice is strongest because exam writers often reward whoever confirms the condition, definition, or table first rather than whoever recognizes the lesson title fastest. The distractors describe good habits, but they are weaker because they do not identify the mistake most likely to create a wrong answer on this topic.', 'Article 334', 'intermediate', TRUE);
