INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('118e20f8-9b66-4c73-8f59-71bf02c28c53', 'pq-084', 'apprentice', 'grounding', 'Grounding', 'Which mistake is most likely to produce a wrong answer about Grounding Concepts on an exam?', '{"A":"Writing the controlling code reference in the margin before comparing answer choices.","B":"Separating the given values from the unknown value before doing a calculation.","C":"Checking whether a special rule modifies a general requirement before finalizing the answer.","D":"Answering from memory before confirming the actual condition, definition, or table that controls the problem."}'::jsonb, 'D', 'The correct choice is strongest because exam writers often reward whoever confirms the condition, definition, or table first rather than whoever recognizes the lesson title fastest. The distractors describe good habits, but they are weaker because they do not identify the mistake most likely to create a wrong answer on this topic.', '250.4', 'intermediate', TRUE);
