INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('8a4669ad-c765-4ae4-ab67-34ecd1965adc', 'pq-113', 'journeyman', 'code', 'Code', 'Which statement best explains why General Rules vs Special Rules matters in daily electrical work?', '{"A":"It helps the electrician make a safer, code-based decision about understand rule hierarchy, apply modifications, navigate efficiently.","B":"It replaces the need to read manufacturer instructions when equipment is listed.","C":"It only matters after the final inspection has already been completed.","D":"It applies only on large commercial projects and not on normal branch-circuit work."}'::jsonb, 'A', 'It helps the electrician make a safer, code-based decision about understand rule hierarchy, apply modifications, navigate efficiently is strongest because General Rules vs Special Rules matters before the final installation choice is made, not after it. The distractors are weaker because listed equipment still requires instructions, inspections do not erase code duties, and this topic is not limited to one project type.', '90.3', 'intermediate', TRUE);
INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('a748dc70-79fa-4bd0-9892-06ef8ccc6803', 'pq-114', 'journeyman', 'code', 'Code', 'When a problem turns on General Rules vs Special Rules, which NEC reference is the best place to start?', '{"A":"Article 100","B":"90.3","C":"90.1","D":"110.3(B)"}'::jsonb, 'B', 'Start with NEC 90.3 because it is the anchor reference attached to General Rules vs Special Rules. The other options may appear nearby in study, but they are weaker because they do not control this lesson as directly as 90.3 does.', '90.3', 'intermediate', TRUE);
