INSERT INTO practice_questions (id, source_key, certification_level, topic_slug, topic_title, question_text, choices, correct_choice, explanation, nec_reference, difficulty_level, is_active) VALUES ('ad0524ed-d3fc-4e36-950e-e23839a4db96', 'pq-288', 'master', 'theory', 'Theory', 'Which statement best explains why Microgrids and Hybrid Systems matters in daily electrical work?', '{"A":"It replaces the need to read manufacturer instructions when equipment is listed.","B":"It only matters after the final inspection has already been completed.","C":"It helps the electrician make a safer, code-based decision about know terminology, understand systems, apply rules.","D":"It applies only on large commercial projects and not on normal branch-circuit work."}'::jsonb, 'C', 'It helps the electrician make a safer, code-based decision about know terminology, understand systems, apply rules is strongest because Microgrids and Hybrid Systems matters before the final installation choice is made, not after it. The distractors are weaker because listed equipment still requires instructions, inspections do not erase code duties, and this topic is not limited to one project type.', '100 (definitions)', 'intermediate', TRUE);
