INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('65b31c7b-2df5-492d-bd83-aa1955ece60d', '17f22a38-65fd-490d-a693-7959af870f49', 1, 'paragraph', 'Learning objective', 'Use Voltage, Current, Resistance, and Ohm''s Law to understand voltage, current, resistance, apply ohm''s law, recognize safety implications. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Voltage, Current, Resistance, and Ohm''s Law to understand voltage, current, resistance, apply ohm''s law, recognize safety implications. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2dba875a-bf77-40d4-8ef2-28bc1823eac6', '17f22a38-65fd-490d-a693-7959af870f49', 2, 'paragraph', 'Why this matters', 'Voltage, Current, Resistance, and Ohm''s Law shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Voltage, Current, Resistance, and Ohm''s Law shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('078720f5-b41d-4983-90b6-dfce65715d1f', '17f22a38-65fd-490d-a693-7959af870f49', 3, 'paragraph', 'Core explanation', 'Voltage, Current, Resistance, and Ohm''s Law explains the electrical relationship that a entry-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Voltage, Current, Resistance, and Ohm''s Law explains the electrical relationship that a entry-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('60dfc0bb-ecf3-4cf4-92aa-fc812c1f02db', '17f22a38-65fd-490d-a693-7959af870f49', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8c29f13c-e6e6-4e95-8ff5-38b87daf25c8', '17f22a38-65fd-490d-a693-7959af870f49', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 100 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Voltage, Current, Resistance, and Ohm''s Law, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 100 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Voltage, Current, Resistance, and Ohm''s Law, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2e85944b-e26a-465e-b080-091d8b07debd', '17f22a38-65fd-490d-a693-7959af870f49', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('abb6069f-a4fc-4404-bfb0-254ef8e89ef8', '17f22a38-65fd-490d-a693-7959af870f49', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a46eed6a-3d67-49b8-90a2-04f989677fae', '17f22a38-65fd-490d-a693-7959af870f49', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Voltage, Current, Resistance, and Ohm''s Law inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 100 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 100, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Voltage, Current, Resistance, and Ohm''s Law inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 100 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 100, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2098c4e8-b4c0-47be-861f-3338971e06e8', '17f22a38-65fd-490d-a693-7959af870f49', 9, 'heading', NULL, 'Key Takeaways', 'Key Takeaways', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2f14f5d0-cdca-4fd6-a8c6-a22479adbf42', '17f22a38-65fd-490d-a693-7959af870f49', 10, 'bullet', NULL, 'Voltage, Current, Resistance, and Ohm''s Law should be tied to its controlling condition rather than memorized as a headline alone.', 'Voltage, Current, Resistance, and Ohm''s Law should be tied to its controlling condition rather than memorized as a headline alone.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('07b8aef3-379f-48ff-b883-efb3b2387e97', '17f22a38-65fd-490d-a693-7959af870f49', 11, 'bullet', NULL, 'NEC Article 100 is the first reference to check when Voltage, Current, Resistance, and Ohm''s Law is tested as an enforceable requirement.', 'NEC Article 100 is the first reference to check when Voltage, Current, Resistance, and Ohm''s Law is tested as an enforceable requirement.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('651b0d57-a25e-4cf7-94b0-a68c764049e1', '17f22a38-65fd-490d-a693-7959af870f49', 12, 'bullet', NULL, 'You will apply Voltage, Current, Resistance, and Ohm''s Law more reliably when you connect the field condition, the code reference, and the resulting decision in one chain.', 'You will apply Voltage, Current, Resistance, and Ohm''s Law more reliably when you connect the field condition, the code reference, and the resulting decision in one chain.', '{}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fc10b2ce-6b86-40a7-aa79-d20da15b5192', '17f22a38-65fd-490d-a693-7959af870f49', 13, 'bullet', NULL, 'The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer. Slow down long enough to confirm the condition before you commit to an answer.', 'The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer. Slow down long enough to confirm the condition before you commit to an answer.', '{}'::jsonb);
