INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fb88f162-1192-451b-8fb4-9dcca5668040', '17f22a38-65fd-490d-a693-7959af870f49', 15, 'callout', 'Question 1', 'What condition tells you that Voltage, Current, Resistance, and Ohm''s Law applies before you choose a wiring or design answer?', 'What condition tells you that Voltage, Current, Resistance, and Ohm''s Law applies before you choose a wiring or design answer?', '{}'::jsonb);
