INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1d09206f-60f4-4acd-8be5-650044266d71', '99d41b80-62a0-471b-9879-4c7028a68acd', 1, 'paragraph', 'Learning objective', 'Use Power, Energy, and Watt''s Law to distinguish power and energy, use watt''s law, apply power ratings to circuits. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Power, Energy, and Watt''s Law to distinguish power and energy, use watt''s law, apply power ratings to circuits. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('13c5df73-db3a-4b11-9da5-e9a203c35faa', '99d41b80-62a0-471b-9879-4c7028a68acd', 2, 'paragraph', 'Why this matters', 'Power, Energy, and Watt''s Law shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Power, Energy, and Watt''s Law shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ce280c54-d738-48cb-898a-57f95a0e7565', '99d41b80-62a0-471b-9879-4c7028a68acd', 3, 'paragraph', 'Core explanation', 'Power, Energy, and Watt''s Law explains the electrical relationship that a entry-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Power, Energy, and Watt''s Law explains the electrical relationship that a entry-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6a77568e-c735-4877-8f59-fbfacba76700', '99d41b80-62a0-471b-9879-4c7028a68acd', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('af696930-8ac4-409a-86a6-7fa76db146c6', '99d41b80-62a0-471b-9879-4c7028a68acd', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 100 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Power, Energy, and Watt''s Law, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 100 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Power, Energy, and Watt''s Law, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('31ecb7cf-6d86-4280-a25f-0e21dddbf3ec', '99d41b80-62a0-471b-9879-4c7028a68acd', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7a6c660d-3d28-423f-93fc-c392fa138d1d', '99d41b80-62a0-471b-9879-4c7028a68acd', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f967c3b1-c49b-4536-93b4-7be5feba663d', '99d41b80-62a0-471b-9879-4c7028a68acd', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Power, Energy, and Watt''s Law inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC Article 100. The best strategy is to underline the operating condition, match it to NEC Article 100, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Power, Energy, and Watt''s Law inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC Article 100. The best strategy is to underline the operating condition, match it to NEC Article 100, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
