INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1d504a6f-95a6-41f5-a30c-e7efe767b128', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 100 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For AC vs DC Power, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 100 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For AC vs DC Power, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f442ff16-b954-4769-9bf9-62bd73e98b3a', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b4abd6e3-ae85-40e5-90dc-56a76bdcdcd3', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('485a8a52-5307-47e8-b14b-a9c75b05e599', '7fd6f5b0-c144-4be6-b93c-af2021f07ad9', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide AC vs DC Power inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 100 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 100, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide AC vs DC Power inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 100 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 100, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
