INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1af16105-0525-4eab-a1fa-fe37434b3a2e', '222483b9-7334-4522-bedb-2a293728377c', 1, 'paragraph', 'Learning objective', 'Use Electrical Hazard Recognition to identify shock hazards, identify arc-flash hazards, understand danger levels. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Electrical Hazard Recognition to identify shock hazards, identify arc-flash hazards, understand danger levels. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["110.3(B)","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8f2f1eb6-7d31-4613-a524-2a30d250013b', '222483b9-7334-4522-bedb-2a293728377c', 2, 'paragraph', 'Why this matters', 'Electrical Hazard Recognition shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Electrical Hazard Recognition shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["110.3(B)","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('29d1a577-89ea-4fed-a73c-493d2fcb8fa5', '222483b9-7334-4522-bedb-2a293728377c', 3, 'paragraph', 'Core explanation', 'Electrical Hazard Recognition is about controlling exposure before a person gets near energized parts. The safe sequence matters: identify the hazard, establish an electrically safe work condition when required, and confirm that protective measures actually match the task. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Electrical Hazard Recognition is about controlling exposure before a person gets near energized parts. The safe sequence matters: identify the hazard, establish an electrically safe work condition when required, and confirm that protective measures actually match the task. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["110.3(B)","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('65720862-c125-47b1-9c68-c27cf1eac38f', '222483b9-7334-4522-bedb-2a293728377c', 4, 'paragraph', 'Key concepts', 'Think in layers: shock protection, arc-flash protection, equipment condition, and work practice. When one layer is weak, the rest of the plan has to compensate or the task should stop until conditions are corrected. The misconception to avoid is treating electrical hazard recognition as vocabulary instead of as an installation or design decision.', 'Think in layers: shock protection, arc-flash protection, equipment condition, and work practice. When one layer is weak, the rest of the plan has to compensate or the task should stop until conditions are corrected. The misconception to avoid is treating electrical hazard recognition as vocabulary instead of as an installation or design decision.', '{"necReferences":["110.3(B)","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8d610df9-103e-4126-a977-ed25d5589ffe', '222483b9-7334-4522-bedb-2a293728377c', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 110.3(B) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Electrical Hazard Recognition, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 110.3(B) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Electrical Hazard Recognition, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["110.3(B)","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('52b8de2c-a1e3-44e6-bbc7-448693254b2c', '222483b9-7334-4522-bedb-2a293728377c', 6, 'paragraph', 'Practical example', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["110.3(B)","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f0ff5dd3-36e0-4419-96a5-2fcd41563fbd', '222483b9-7334-4522-bedb-2a293728377c', 7, 'paragraph', 'Common mistakes', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["110.3(B)","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7d52c60b-40be-4042-8a41-1b8dcb01c8b0', '222483b9-7334-4522-bedb-2a293728377c', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Electrical Hazard Recognition inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 110.3(B). The best strategy is to underline the operating condition, match it to NEC 110.3(B), and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Electrical Hazard Recognition inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 110.3(B). The best strategy is to underline the operating condition, match it to NEC 110.3(B), and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["110.3(B)","90.1"]}'::jsonb);
