INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('99fd27fe-6998-4ab6-8dff-4338fec590d6', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 6, 'paragraph', 'Practical example', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["110.4","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('87835229-c286-46b9-ac58-d630d33d7979', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 7, 'paragraph', 'Common mistakes', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["110.4","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('26e59a9d-e154-4827-9db4-a295eea2dcdc', '2be6d8d4-ff37-4d29-a935-bca89d99ff50', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide PPE and Lockout-Tagout inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 110.4. The best strategy is to underline the operating condition, match it to NEC 110.4, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide PPE and Lockout-Tagout inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 110.4. The best strategy is to underline the operating condition, match it to NEC 110.4, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["110.4","90.1"]}'::jsonb);
