INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('90fb0400-acff-4447-a0ae-a789a03ceb96', 'e7f99f77-30e4-464e-9ede-d016be784019', 1, 'paragraph', 'Learning objective', 'Use Arc Flash and Protection to understand arc flash hazard, select arc-rated clothing, know protection requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Arc Flash and Protection to understand arc flash hazard, select arc-rated clothing, know protection requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["110.16","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('70d7b65a-acab-4a1a-8158-af9477ba0b66', 'e7f99f77-30e4-464e-9ede-d016be784019', 2, 'paragraph', 'Why this matters', 'Arc Flash and Protection shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Arc Flash and Protection shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["110.16","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('767b6894-6831-41b0-9459-387b9906e292', 'e7f99f77-30e4-464e-9ede-d016be784019', 3, 'paragraph', 'Core explanation', 'Arc Flash and Protection is about controlling exposure before a person gets near energized parts. The safe sequence matters: identify the hazard, establish an electrically safe work condition when required, and confirm that protective measures actually match the task. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Arc Flash and Protection is about controlling exposure before a person gets near energized parts. The safe sequence matters: identify the hazard, establish an electrically safe work condition when required, and confirm that protective measures actually match the task. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["110.16","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('40c5faff-ce42-420a-bcb3-210328466f64', 'e7f99f77-30e4-464e-9ede-d016be784019', 4, 'paragraph', 'Key concepts', 'Think in layers: shock protection, arc-flash protection, equipment condition, and work practice. When one layer is weak, the rest of the plan has to compensate or the task should stop until conditions are corrected. The misconception to avoid is treating arc flash and protection as vocabulary instead of as an installation or design decision.', 'Think in layers: shock protection, arc-flash protection, equipment condition, and work practice. When one layer is weak, the rest of the plan has to compensate or the task should stop until conditions are corrected. The misconception to avoid is treating arc flash and protection as vocabulary instead of as an installation or design decision.', '{"necReferences":["110.16","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('dd5dd63a-b1ac-4e06-a80e-4ed146fd9525', 'e7f99f77-30e4-464e-9ede-d016be784019', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 110.16 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Arc Flash and Protection, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 110.16 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Arc Flash and Protection, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["110.16","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('561fcb7a-e7ce-4d35-a131-4b8bfe10e0d6', 'e7f99f77-30e4-464e-9ede-d016be784019', 6, 'paragraph', 'Practical example', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["110.16","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('617f6a08-045e-4f0c-826f-3dc3a44e7028', 'e7f99f77-30e4-464e-9ede-d016be784019', 7, 'paragraph', 'Common mistakes', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["110.16","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fe9c7ce4-2938-4fb0-b194-0876e70d5ce8', 'e7f99f77-30e4-464e-9ede-d016be784019', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Arc Flash and Protection inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 110.16. The best strategy is to underline the operating condition, match it to NEC 110.16, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Arc Flash and Protection inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 110.16. The best strategy is to underline the operating condition, match it to NEC 110.16, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["110.16","90.1"]}'::jsonb);
