INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('01bd09f6-d244-4bbe-8bdf-36e79c9d07a0', 'a634384e-cd8a-4305-acc1-7001313e16c9', 13, 'bullet', NULL, 'The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you. Slow down long enough to confirm the condition before you commit to an answer.', 'The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you. Slow down long enough to confirm the condition before you commit to an answer.', '{}'::jsonb);
