INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('03a1e46d-af1f-4c82-8e0c-547708e9e94e', 'c7c4d9a3-7b44-4f81-9915-8df740dc3747', 1, 'paragraph', 'Learning objective', 'Use How the NEC Is Organized to navigate nec structure, understand chapters and articles, use indexes effectively. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use How the NEC Is Organized to navigate nec structure, understand chapters and articles, use indexes effectively. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["90.1","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('daafa425-b3b0-415a-a42c-a7ab7745e3b7', 'c7c4d9a3-7b44-4f81-9915-8df740dc3747', 2, 'paragraph', 'Why this matters', 'How the NEC Is Organized shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'How the NEC Is Organized shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["90.1","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c66873ec-e835-4dff-a860-667216f75369', 'c7c4d9a3-7b44-4f81-9915-8df740dc3747', 3, 'paragraph', 'Core explanation', 'How the NEC Is Organized teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'How the NEC Is Organized teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["90.1","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b6b9cd98-3769-4679-928c-4a7deac46f21', 'c7c4d9a3-7b44-4f81-9915-8df740dc3747', 4, 'paragraph', 'Key concepts', 'Use code words carefully. Terms such as permitted, required, identified, listed, labeled, and approved are not interchangeable, and exam writers rely on those distinctions when they build distractors. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Use code words carefully. Terms such as permitted, required, identified, listed, labeled, and approved are not interchangeable, and exam writers rely on those distinctions when they build distractors. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["90.1","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('65dab1b9-8486-499a-8edc-3b0d8e8c3c23', 'c7c4d9a3-7b44-4f81-9915-8df740dc3747', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 90.1 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For How the NEC Is Organized, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 90.1 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For How the NEC Is Organized, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["90.1","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d8b39480-f189-4706-a88d-aa81e2898e1c', 'c7c4d9a3-7b44-4f81-9915-8df740dc3747', 6, 'paragraph', 'Practical example', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["90.1","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e54284ee-cecc-4525-8ecf-a918c34fcd6a', 'c7c4d9a3-7b44-4f81-9915-8df740dc3747', 7, 'paragraph', 'Common mistakes', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["90.1","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7aed33cb-baca-4729-a2e8-5a5bb58ef547', 'c7c4d9a3-7b44-4f81-9915-8df740dc3747', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide How the NEC Is Organized inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 90.1. The best strategy is to underline the operating condition, match it to NEC 90.1, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide How the NEC Is Organized inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 90.1. The best strategy is to underline the operating condition, match it to NEC 90.1, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["90.1","Article 100"]}'::jsonb);
