INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1f185a7f-a966-416b-b320-a6f4b7f5de02', 'cc7cdfc2-7090-4988-a2e1-541bfd9bf6ac', 1, 'paragraph', 'Learning objective', 'Use Article 100 Definitions to learn key definitions, apply definitions correctly, understand term relationships. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Article 100 Definitions to learn key definitions, apply definitions correctly, understand term relationships. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b874ab05-efa8-4c53-9d60-f2777c59a418', 'cc7cdfc2-7090-4988-a2e1-541bfd9bf6ac', 2, 'paragraph', 'Why this matters', 'Article 100 Definitions shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Article 100 Definitions shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('86dcd02b-78b8-4dc0-8b9e-08b4a323e5a1', 'cc7cdfc2-7090-4988-a2e1-541bfd9bf6ac', 3, 'paragraph', 'Core explanation', 'Article 100 Definitions teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Article 100 Definitions teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8e164db7-6341-4bcb-955f-59e2c4167a1a', 'cc7cdfc2-7090-4988-a2e1-541bfd9bf6ac', 4, 'paragraph', 'Key concepts', 'Use code words carefully. Terms such as permitted, required, identified, listed, labeled, and approved are not interchangeable, and exam writers rely on those distinctions when they build distractors. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Use code words carefully. Terms such as permitted, required, identified, listed, labeled, and approved are not interchangeable, and exam writers rely on those distinctions when they build distractors. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('32a24614-0567-4909-afea-3e00e7b080a3', 'cc7cdfc2-7090-4988-a2e1-541bfd9bf6ac', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 100 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Article 100 Definitions, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 100 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Article 100 Definitions, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e174b7e9-e0a7-4ef7-a55f-bc527f37f2c4', 'cc7cdfc2-7090-4988-a2e1-541bfd9bf6ac', 6, 'paragraph', 'Practical example', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7ea52d1a-ee92-4ed2-99c0-20caa44ad750', 'cc7cdfc2-7090-4988-a2e1-541bfd9bf6ac', 7, 'paragraph', 'Common mistakes', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. When you review misses, look for the first step where the condition or reference was ignored.', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d322016f-b94d-456b-bc41-ab16fd64f6dc', 'cc7cdfc2-7090-4988-a2e1-541bfd9bf6ac', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Article 100 Definitions inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 100 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 100, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Article 100 Definitions inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 100 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 100, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
