INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('faf08fe6-e51a-4c4d-9564-9ed34976beae', '03b78478-454d-4802-8042-548cf1f52ccf', 2, 'paragraph', 'Why this matters', 'Code Lookup Strategies shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Code Lookup Strategies shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f7b3f65a-2a00-4348-9d67-591c4ee77ebd', '03b78478-454d-4802-8042-548cf1f52ccf', 3, 'paragraph', 'Core explanation', 'Code Lookup Strategies teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Code Lookup Strategies teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
