INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a9cab16b-e724-4f0a-abe4-7a626a77e39e', 'b6181626-699d-4544-b78a-2b5760262fd8', 1, 'paragraph', 'Learning objective', 'Use Raceways: Conduit and Tubing to identify raceway types, know installation rules, understand support requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Raceways: Conduit and Tubing to identify raceway types, know installation rules, understand support requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9523cee3-b721-4e37-8138-5f19c91113d2', 'b6181626-699d-4544-b78a-2b5760262fd8', 2, 'paragraph', 'Why this matters', 'Raceways: Conduit and Tubing shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Raceways: Conduit and Tubing shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('27f919ee-5fb3-416b-9b11-04def91f8ab9', 'b6181626-699d-4544-b78a-2b5760262fd8', 3, 'paragraph', 'Core explanation', 'Raceways: Conduit and Tubing explains the electrical relationship that a entry-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Raceways: Conduit and Tubing explains the electrical relationship that a entry-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('93529993-aad6-4137-b9d4-dc5cd9538513', 'b6181626-699d-4544-b78a-2b5760262fd8', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The misconception to avoid is treating raceways: conduit and tubing as vocabulary instead of as an installation or design decision.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The misconception to avoid is treating raceways: conduit and tubing as vocabulary instead of as an installation or design decision.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('cd02d739-f55d-48ee-817b-6f6183907f5c', 'b6181626-699d-4544-b78a-2b5760262fd8', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 300.11 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Raceways: Conduit and Tubing, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 300.11 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Raceways: Conduit and Tubing, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('38a0684b-28dc-4904-a04a-ddfe8f036200', 'b6181626-699d-4544-b78a-2b5760262fd8', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('acaba07c-1afb-4e26-8fce-30a69a183426', 'b6181626-699d-4544-b78a-2b5760262fd8', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9ae3cf65-bf68-4a02-b0b5-8fd35cb6000f', 'b6181626-699d-4544-b78a-2b5760262fd8', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Raceways: Conduit and Tubing inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 300.11. The best strategy is to underline the operating condition, match it to NEC 300.11, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Raceways: Conduit and Tubing inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 300.11. The best strategy is to underline the operating condition, match it to NEC 300.11, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["300.11"]}'::jsonb);
