INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5114e0e2-f268-4c9c-8471-127e4328de04', 'f5a4f114-76ce-4249-b807-323ead8aa03b', 1, 'paragraph', 'Learning objective', 'Use Cable Types and Assemblies to recognize cable types, know permitted uses, understand installation rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Cable Types and Assemblies to recognize cable types, know permitted uses, understand installation rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 334","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('643282a6-abe6-4b5b-bc11-90d94a02a6c3', 'f5a4f114-76ce-4249-b807-323ead8aa03b', 2, 'paragraph', 'Why this matters', 'Cable Types and Assemblies shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Cable Types and Assemblies shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 334","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5b47558d-f43a-4b7c-ae90-c8661e62aebe', 'f5a4f114-76ce-4249-b807-323ead8aa03b', 3, 'paragraph', 'Core explanation', 'Cable Types and Assemblies covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Cable Types and Assemblies covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["Article 334","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2dffaaf9-89b7-424e-971d-c73e319b5362', 'f5a4f114-76ce-4249-b807-323ead8aa03b', 4, 'paragraph', 'Key concepts', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating cable types and assemblies as vocabulary instead of as an installation or design decision.', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating cable types and assemblies as vocabulary instead of as an installation or design decision.', '{"necReferences":["Article 334","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('763fddf2-7a5d-4969-ba63-cea2a19a0212', 'f5a4f114-76ce-4249-b807-323ead8aa03b', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 334 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Cable Types and Assemblies, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 334 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Cable Types and Assemblies, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 334","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('153421e9-3db9-41a4-a6dc-4e646bcaf4d3', 'f5a4f114-76ce-4249-b807-323ead8aa03b', 6, 'paragraph', 'Practical example', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["Article 334","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('eb6714da-fab2-4199-86eb-beddd476d406', 'f5a4f114-76ce-4249-b807-323ead8aa03b', 7, 'paragraph', 'Common mistakes', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["Article 334","90.1"]}'::jsonb);
