INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('58a43027-aa8f-4326-a747-e583d324c023', '8866cfbe-25d6-476a-b20b-5e66dda9e9fe', 3, 'paragraph', 'Core explanation', 'Boxes and Conduit Bodies covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Boxes and Conduit Bodies covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["314.16"]}'::jsonb);
