INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('01e0be42-ec5d-41eb-b418-313a3ad2c922', '8866cfbe-25d6-476a-b20b-5e66dda9e9fe', 6, 'paragraph', 'Practical example', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6c56f2ce-46ce-40ac-993a-eb227cda36f8', '8866cfbe-25d6-476a-b20b-5e66dda9e9fe', 7, 'paragraph', 'Common mistakes', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. When you review misses, look for the first step where the condition or reference was ignored.', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9258c4f2-8348-4f35-a575-f79b4e56eab8', '8866cfbe-25d6-476a-b20b-5e66dda9e9fe', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Boxes and Conduit Bodies inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 314.16 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 314.16, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Boxes and Conduit Bodies inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 314.16 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 314.16, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["314.16"]}'::jsonb);
