INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('769586fe-f66f-4d17-bb7c-8fc8bf654588', '8866cfbe-25d6-476a-b20b-5e66dda9e9fe', 13, 'bullet', NULL, 'The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer. Slow down long enough to confirm the condition before you commit to an answer.', 'The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer. Slow down long enough to confirm the condition before you commit to an answer.', '{}'::jsonb);
