INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('69d8af16-32bf-41eb-84ad-fbf5056ac84f', '64ab31da-e875-4f43-9666-0c4c1c14384c', 1, 'paragraph', 'Learning objective', 'Use Conductor Sizing Basics to use ampacity tables, select wire sizes, understand derating factors. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Conductor Sizing Basics to use ampacity tables, select wire sizes, understand derating factors. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8598bfa6-0ad7-468d-9c93-1e896bb730de', '64ab31da-e875-4f43-9666-0c4c1c14384c', 2, 'paragraph', 'Why this matters', 'Conductor Sizing Basics shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Conductor Sizing Basics shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('70dc2e4b-a4d4-4524-bc28-c309794c2a07', '64ab31da-e875-4f43-9666-0c4c1c14384c', 3, 'paragraph', 'Core explanation', 'Conductor Sizing Basics covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Conductor Sizing Basics covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1c36674c-60f5-4f8b-8677-255106b69ecd', '64ab31da-e875-4f43-9666-0c4c1c14384c', 4, 'paragraph', 'Key concepts', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f2a35cca-d67d-4f19-a1fe-b0ee483775e1', '64ab31da-e875-4f43-9666-0c4c1c14384c', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 310.14 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Conductor Sizing Basics, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 310.14 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Conductor Sizing Basics, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e0f54dff-6106-47db-9c13-efb1b1b4c032', '64ab31da-e875-4f43-9666-0c4c1c14384c', 6, 'paragraph', 'Practical example', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7461104a-fcb7-4e62-9248-130e61a798d7', '64ab31da-e875-4f43-9666-0c4c1c14384c', 7, 'paragraph', 'Common mistakes', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('297341ec-34b3-4733-ab8b-62e3f785e962', '64ab31da-e875-4f43-9666-0c4c1c14384c', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Conductor Sizing Basics inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 310.14. The best strategy is to underline the operating condition, match it to NEC 310.14, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Conductor Sizing Basics inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 310.14. The best strategy is to underline the operating condition, match it to NEC 310.14, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["310.14"]}'::jsonb);
