INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('aad037c6-388b-4d53-a5a0-b28bd9de8639', '76a8353c-4bc7-4be1-b308-65e770cfbdae', 13, 'bullet', NULL, 'The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you. Slow down long enough to confirm the condition before you commit to an answer.', 'The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you. Slow down long enough to confirm the condition before you commit to an answer.', '{}'::jsonb);
