INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d6c56b87-a3b3-40eb-8cc4-9494172fceb6', '06a1baf4-4307-46fd-91c8-280feabf62d2', 1, 'paragraph', 'Learning objective', 'Use GFCI and AFCI Protection to know gfci requirements, know afci requirements, understand protection zones. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use GFCI and AFCI Protection to know gfci requirements, know afci requirements, understand protection zones. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["210.8","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e37b84b5-88e6-4ca0-b382-ac8f7b117319', '06a1baf4-4307-46fd-91c8-280feabf62d2', 2, 'paragraph', 'Why this matters', 'GFCI and AFCI Protection shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'GFCI and AFCI Protection shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["210.8","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('48d93ea1-450d-4a34-a9b3-53b87518d76e', '06a1baf4-4307-46fd-91c8-280feabf62d2', 3, 'paragraph', 'Core explanation', 'GFCI and AFCI Protection covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'GFCI and AFCI Protection covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["210.8","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c9119cf9-36cb-40b2-9bba-2ca0451b17eb', '06a1baf4-4307-46fd-91c8-280feabf62d2', 4, 'paragraph', 'Key concepts', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["210.8","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9438adc0-a56f-41f1-81fc-5650e12d217c', '06a1baf4-4307-46fd-91c8-280feabf62d2', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 210.8 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For GFCI and AFCI Protection, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 210.8 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For GFCI and AFCI Protection, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["210.8","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('66d4a2e1-305d-47e3-b9d6-6bea8c40682b', '06a1baf4-4307-46fd-91c8-280feabf62d2', 6, 'paragraph', 'Practical example', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["210.8","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('20d6cf3b-9eaa-4a6e-bcb3-c635a910cb72', '06a1baf4-4307-46fd-91c8-280feabf62d2', 7, 'paragraph', 'Common mistakes', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. When you review misses, look for the first step where the condition or reference was ignored.', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["210.8","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4df6e414-e94c-4504-bceb-5319d2e20b67', '06a1baf4-4307-46fd-91c8-280feabf62d2', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide GFCI and AFCI Protection inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 210.8 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 210.8, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide GFCI and AFCI Protection inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 210.8 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 210.8, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["210.8","210.19(A)"]}'::jsonb);
