INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5560b9c4-e0d9-4d2f-81fb-3c441c3582f0', '59d05371-8db7-4880-a2b4-a08acf80de59', 1, 'paragraph', 'Learning objective', 'Use Dwelling Receptacle Requirements to calculate receptacle spacing, know room requirements, apply placement rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Dwelling Receptacle Requirements to calculate receptacle spacing, know room requirements, apply placement rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["210.52","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b684ac71-bfc8-4daf-9ecd-1f33e3082e83', '59d05371-8db7-4880-a2b4-a08acf80de59', 2, 'paragraph', 'Why this matters', 'Dwelling Receptacle Requirements shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Dwelling Receptacle Requirements shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["210.52","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f6d246ce-0dd3-4bdb-99f1-6088a9f0a395', '59d05371-8db7-4880-a2b4-a08acf80de59', 3, 'paragraph', 'Core explanation', 'Dwelling Receptacle Requirements explains the electrical relationship that a entry-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Dwelling Receptacle Requirements explains the electrical relationship that a entry-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["210.52","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('048319c2-8921-4ede-8ebe-ed6e0fb34783', '59d05371-8db7-4880-a2b4-a08acf80de59', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["210.52","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('110c81a9-32d7-461a-9013-243eff6acddb', '59d05371-8db7-4880-a2b4-a08acf80de59', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 210.52 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Dwelling Receptacle Requirements, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 210.52 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Dwelling Receptacle Requirements, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["210.52","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('10254048-379d-4fc1-8189-48007e2539f2', '59d05371-8db7-4880-a2b4-a08acf80de59', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["210.52","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5226ffec-7aee-4de3-8f0b-a2d4aeb45faf', '59d05371-8db7-4880-a2b4-a08acf80de59', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["210.52","210.19(A)"]}'::jsonb);
