INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1061d6ab-6d6f-4f51-88f5-ad5c41736b55', 'cc9f3a19-fc0e-4919-aec3-c764966e66da', 1, 'paragraph', 'Learning objective', 'Use Box Fill Calculations to calculate box volume, count conductors correctly, know fill limitations. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Box Fill Calculations to calculate box volume, count conductors correctly, know fill limitations. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('596f2df1-08cd-4855-87c0-01706b9a0c48', 'cc9f3a19-fc0e-4919-aec3-c764966e66da', 2, 'paragraph', 'Why this matters', 'Box Fill Calculations shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Box Fill Calculations shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('aefa8613-85f3-49a5-b250-0f19245e6ec4', 'cc9f3a19-fc0e-4919-aec3-c764966e66da', 3, 'paragraph', 'Core explanation', 'Box Fill Calculations covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Box Fill Calculations covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d6287a3f-6e80-4762-bb77-6fa7f48e4c44', 'cc9f3a19-fc0e-4919-aec3-c764966e66da', 4, 'paragraph', 'Key concepts', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('73652ca4-9e7f-41d3-b025-88053ad3c74e', 'cc9f3a19-fc0e-4919-aec3-c764966e66da', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 314.16 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Box Fill Calculations, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 314.16 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Box Fill Calculations, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('90d6cfd9-d278-4f82-8bdc-c5d3e570aa33', 'cc9f3a19-fc0e-4919-aec3-c764966e66da', 6, 'paragraph', 'Practical example', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('468cf011-b1ba-4723-af54-cb571247b372', 'cc9f3a19-fc0e-4919-aec3-c764966e66da', 7, 'paragraph', 'Common mistakes', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["314.16"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('aa045f2c-bd5c-485b-9b58-032cbd458779', 'cc9f3a19-fc0e-4919-aec3-c764966e66da', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Box Fill Calculations inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 314.16. The best strategy is to underline the operating condition, match it to NEC 314.16, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Box Fill Calculations inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 314.16. The best strategy is to underline the operating condition, match it to NEC 314.16, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["314.16"]}'::jsonb);
