INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3a692a52-be62-4768-80bb-a1a8073528e1', '346333a4-9bef-4d77-9057-53abe7cd09a5', 1, 'paragraph', 'Learning objective', 'Use Grounding Concepts to understand grounding purpose, know safety benefits, apply basic rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Grounding Concepts to understand grounding purpose, know safety benefits, apply basic rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d4bc4b28-f6ef-4869-8424-b58100ff7767', '346333a4-9bef-4d77-9057-53abe7cd09a5', 2, 'paragraph', 'Why this matters', 'Grounding Concepts shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Grounding Concepts shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a8e1a009-c423-4675-b0ea-5b0a8cfec575', '346333a4-9bef-4d77-9057-53abe7cd09a5', 3, 'paragraph', 'Core explanation', 'Grounding Concepts deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Grounding Concepts deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9832dbe4-0573-4507-8e70-6ab4529cc98e', '346333a4-9bef-4d77-9057-53abe7cd09a5', 4, 'paragraph', 'Key concepts', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('11bf0e47-59fd-4866-adc2-ed5e84120dbc', '346333a4-9bef-4d77-9057-53abe7cd09a5', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 250.4 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Grounding Concepts, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 250.4 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Grounding Concepts, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8d65430d-f772-46b1-8b16-2925bce98c99', '346333a4-9bef-4d77-9057-53abe7cd09a5', 6, 'paragraph', 'Practical example', 'This topic matters when you connect service equipment, feeders, separate buildings, electrodes, and equipment grounding conductors. Good grounding work is deliberate, continuous, and sized to perform under fault conditions rather than by appearance alone. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'This topic matters when you connect service equipment, feeders, separate buildings, electrodes, and equipment grounding conductors. Good grounding work is deliberate, continuous, and sized to perform under fault conditions rather than by appearance alone. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fd255824-6917-45ab-beac-ccd227317baf', '346333a4-9bef-4d77-9057-53abe7cd09a5', 7, 'paragraph', 'Common mistakes', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["250.4"]}'::jsonb);
