INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1ca7c865-9483-4c4f-93d4-82bcd7410b62', '3410c60f-4be5-43be-940c-374af2df9cb7', 3, 'paragraph', 'Core explanation', 'Equipment Grounding Conductors deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Equipment Grounding Conductors deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["250.118","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9fcf935d-173e-4d65-b716-763a5ff88523', '3410c60f-4be5-43be-940c-374af2df9cb7', 4, 'paragraph', 'Key concepts', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["250.118","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('06d7a413-e06e-469e-a1b0-80d89419a584', '3410c60f-4be5-43be-940c-374af2df9cb7', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 250.118 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Equipment Grounding Conductors, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 250.118 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Equipment Grounding Conductors, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["250.118","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1c13fc7a-267f-4b86-b1f7-0a036339521b', '3410c60f-4be5-43be-940c-374af2df9cb7', 6, 'paragraph', 'Practical example', 'This topic matters when you connect service equipment, feeders, separate buildings, electrodes, and equipment grounding conductors. Good grounding work is deliberate, continuous, and sized to perform under fault conditions rather than by appearance alone. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'This topic matters when you connect service equipment, feeders, separate buildings, electrodes, and equipment grounding conductors. Good grounding work is deliberate, continuous, and sized to perform under fault conditions rather than by appearance alone. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["250.118","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2cd2235b-2fd0-48f6-8d91-1ec450533e02', '3410c60f-4be5-43be-940c-374af2df9cb7', 7, 'paragraph', 'Common mistakes', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. When you review misses, look for the first step where the condition or reference was ignored.', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["250.118","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3664e458-1dbc-474a-a9da-70cc7a943538', '3410c60f-4be5-43be-940c-374af2df9cb7', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Equipment Grounding Conductors inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 250.118 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 250.118, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Equipment Grounding Conductors inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 250.118 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 250.118, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["250.118","250.4"]}'::jsonb);
