INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5c2ff1c1-0dec-4f8c-8c95-f013b9d6c8d9', '607f49a2-fe24-41b3-b22c-55439726f11f', 1, 'paragraph', 'Learning objective', 'Use Residential Grounding to understand service grounding, know feeder requirements, apply dwelling rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Residential Grounding to understand service grounding, know feeder requirements, apply dwelling rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["250.24","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9a8fdc8e-3898-42e3-9d39-ff29894be28f', '607f49a2-fe24-41b3-b22c-55439726f11f', 2, 'paragraph', 'Why this matters', 'Residential Grounding shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Residential Grounding shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["250.24","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d41e6956-e633-452a-b17e-ec51777a3a30', '607f49a2-fe24-41b3-b22c-55439726f11f', 3, 'paragraph', 'Core explanation', 'Residential Grounding deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Residential Grounding deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["250.24","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1bcfb41d-423c-45b2-bd58-1a29fc31e6ec', '607f49a2-fe24-41b3-b22c-55439726f11f', 4, 'paragraph', 'Key concepts', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The misconception to avoid is treating residential grounding as vocabulary instead of as an installation or design decision.', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The misconception to avoid is treating residential grounding as vocabulary instead of as an installation or design decision.', '{"necReferences":["250.24","250.4"]}'::jsonb);
