INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3fa1f0f2-7014-4f56-b294-73dba657132e', '607f49a2-fe24-41b3-b22c-55439726f11f', 7, 'paragraph', 'Common mistakes', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["250.24","250.4"]}'::jsonb);
