INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1addd90d-6149-4ecd-aeb1-bd00dfa14cbd', '12551330-d5a7-49e6-9f98-f1dced972031', 7, 'paragraph', 'Common mistakes', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["110.5","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c03008f2-a7db-44c1-9b0a-1c763729662d', '12551330-d5a7-49e6-9f98-f1dced972031', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Essential Tools inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 110.5. The best strategy is to underline the operating condition, match it to NEC 110.5, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Essential Tools inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 110.5. The best strategy is to underline the operating condition, match it to NEC 110.5, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["110.5","90.1"]}'::jsonb);
