INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f888d970-34a5-4e74-a8eb-8662e7ffadf3', '12551330-d5a7-49e6-9f98-f1dced972031', 13, 'bullet', NULL, 'The misconception to avoid is treating essential tools as vocabulary instead of as an installation or design decision. Slow down long enough to confirm the condition before you commit to an answer.', 'The misconception to avoid is treating essential tools as vocabulary instead of as an installation or design decision. Slow down long enough to confirm the condition before you commit to an answer.', '{}'::jsonb);
