INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('33b3707d-cdc0-4055-b98e-936817c7c49d', '4f03de9d-bd5e-4295-b815-c6047b0e41d7', 1, 'paragraph', 'Learning objective', 'Use Measurements and Fractions to work with fractions, convert units, make accurate measurements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Measurements and Fractions to work with fractions, convert units, make accurate measurements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('02a5f057-0ee8-4719-bf37-1add273fc758', '4f03de9d-bd5e-4295-b815-c6047b0e41d7', 2, 'paragraph', 'Why this matters', 'Measurements and Fractions shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Measurements and Fractions shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f84e648c-8328-4ad6-990e-61705c3c77ad', '4f03de9d-bd5e-4295-b815-c6047b0e41d7', 3, 'paragraph', 'Core explanation', 'Measurements and Fractions explains the electrical relationship that a entry-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Measurements and Fractions explains the electrical relationship that a entry-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a1ad995c-eda1-422d-959d-002a031f03b5', '4f03de9d-bd5e-4295-b815-c6047b0e41d7', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The misconception to avoid is treating measurements and fractions as vocabulary instead of as an installation or design decision.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The misconception to avoid is treating measurements and fractions as vocabulary instead of as an installation or design decision.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8695ac76-fe35-4169-920b-4a09698a5631', '4f03de9d-bd5e-4295-b815-c6047b0e41d7', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 100 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Measurements and Fractions, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 100 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Measurements and Fractions, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3f401064-366e-4cfe-b9d3-2e663af58c42', '4f03de9d-bd5e-4295-b815-c6047b0e41d7', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('69c2a6c7-4855-4066-80f8-5d2916709e5b', '4f03de9d-bd5e-4295-b815-c6047b0e41d7', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
