INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6671ce8b-97e9-4836-8f7d-f3c713ba67f7', 'c5d4d15e-53d8-4dde-ac7c-5b6cc7a58042', 3, 'paragraph', 'Core explanation', 'Trade Math Basics combines code knowledge with practical field judgment. A strong answer shows that you understand both the purpose of the rule and the installation decision that follows from it. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Trade Math Basics combines code knowledge with practical field judgment. A strong answer shows that you understand both the purpose of the rule and the installation decision that follows from it. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["300.17","300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('efc8d780-e32b-4704-a8a8-481ebe30d979', 'c5d4d15e-53d8-4dde-ac7c-5b6cc7a58042', 4, 'paragraph', 'Key concepts', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The misconception to avoid is treating trade math basics as vocabulary instead of as an installation or design decision.', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The misconception to avoid is treating trade math basics as vocabulary instead of as an installation or design decision.', '{"necReferences":["300.17","300.11"]}'::jsonb);
