INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8d0cdca8-d094-41a0-a957-6c969cfe0733', '33f83326-3b9f-4e1d-b506-d7fd9331fe72', 1, 'paragraph', 'Learning objective', 'Use Introduction to Load Calculations to understand demand factors, perform simple calculations, know allowable methods. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Introduction to Load Calculations to understand demand factors, perform simple calculations, know allowable methods. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["220.12","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d96abdb0-3331-452e-b5a5-7ae5c661b8ea', '33f83326-3b9f-4e1d-b506-d7fd9331fe72', 2, 'paragraph', 'Why this matters', 'Introduction to Load Calculations shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Introduction to Load Calculations shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["220.12","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3e6bc8fa-ff2e-469e-b44a-6ea31259568a', '33f83326-3b9f-4e1d-b506-d7fd9331fe72', 3, 'paragraph', 'Core explanation', 'Introduction to Load Calculations is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Introduction to Load Calculations is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["220.12","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9c6cf833-8e12-4172-b9a0-ef7c7250e31d', '33f83326-3b9f-4e1d-b506-d7fd9331fe72', 4, 'paragraph', 'Key concepts', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["220.12","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a4e6be99-fb0f-4897-a307-15304ab497df', '33f83326-3b9f-4e1d-b506-d7fd9331fe72', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 220.12 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Introduction to Load Calculations, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 220.12 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Introduction to Load Calculations, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["220.12","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b5f72f21-a04d-498c-9a50-a1afd8bcd9ad', '33f83326-3b9f-4e1d-b506-d7fd9331fe72', 6, 'paragraph', 'Practical example', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["220.12","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('81f054ff-6900-4394-95e3-34a28fde5757', '33f83326-3b9f-4e1d-b506-d7fd9331fe72', 7, 'paragraph', 'Common mistakes', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["220.12","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('334f6620-8545-4b4c-8aa1-51c20fc56b55', '33f83326-3b9f-4e1d-b506-d7fd9331fe72', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Introduction to Load Calculations inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 220.12. The best strategy is to underline the operating condition, match it to NEC 220.12, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Introduction to Load Calculations inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 220.12. The best strategy is to underline the operating condition, match it to NEC 220.12, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["220.12","220.40"]}'::jsonb);
