INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f39c402e-187e-40fc-88e6-2ad7324c9b4b', '864c8b5a-d90f-44e7-bf6c-ad4712859213', 4, 'paragraph', 'Key concepts', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["220.52","220.40"]}'::jsonb);
