INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('943a0a76-e36e-48a0-b635-303668d83861', '864c8b5a-d90f-44e7-bf6c-ad4712859213', 6, 'paragraph', 'Practical example', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["220.52","220.40"]}'::jsonb);
