INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7969a2ad-ac3d-4319-b67d-b7abf808882a', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 1, 'paragraph', 'Learning objective', 'Use General Rules vs Special Rules to understand rule hierarchy, apply modifications, navigate efficiently. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use General Rules vs Special Rules to understand rule hierarchy, apply modifications, navigate efficiently. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3ff51656-6510-49f9-9950-cd8a882f3d5c', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 2, 'paragraph', 'Why this matters', 'General Rules vs Special Rules shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'General Rules vs Special Rules shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3ab45332-564e-4a52-b975-b42bba20b8e6', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 3, 'paragraph', 'Core explanation', 'General Rules vs Special Rules teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'General Rules vs Special Rules teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ab2d426d-f32c-413c-9961-555e21780c52', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 4, 'paragraph', 'Key concepts', 'Use code words carefully. Terms such as permitted, required, identified, listed, labeled, and approved are not interchangeable, and exam writers rely on those distinctions when they build distractors. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Use code words carefully. Terms such as permitted, required, identified, listed, labeled, and approved are not interchangeable, and exam writers rely on those distinctions when they build distractors. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4527e977-8d86-44c6-b807-35306195ba8c', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 90.3 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For General Rules vs Special Rules, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 90.3 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For General Rules vs Special Rules, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('dd21453b-7416-4adb-865d-bdd7da3f2c4d', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 6, 'paragraph', 'Practical example', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2735b963-b4cd-42df-8565-6c28d6743f1d', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 7, 'paragraph', 'Common mistakes', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7b7ddb31-e626-4a7d-aa76-05db0c3169d8', '40f011ac-7be9-4e37-bd7c-91607a241a3e', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide General Rules vs Special Rules inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 90.3. The best strategy is to underline the operating condition, match it to NEC 90.3, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide General Rules vs Special Rules inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 90.3. The best strategy is to underline the operating condition, match it to NEC 90.3, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
