INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('919012b6-6762-4967-8dd8-5fbcd17deec9', '38a5b1ac-e91d-491f-b720-75c70d567b19', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 90.3 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Exception Hunting, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 90.3 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Exception Hunting, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0d811506-332c-43d9-bf3d-dc0222e4c967', '38a5b1ac-e91d-491f-b720-75c70d567b19', 6, 'paragraph', 'Practical example', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('428fd12f-4828-473c-8479-01c6b7ffd9cc', '38a5b1ac-e91d-491f-b720-75c70d567b19', 7, 'paragraph', 'Common mistakes', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('47dcf0ae-2469-40f6-a7ab-7bbc26ae06f1', '38a5b1ac-e91d-491f-b720-75c70d567b19', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Exception Hunting inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 90.3. The best strategy is to underline the operating condition, match it to NEC 90.3, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Exception Hunting inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 90.3. The best strategy is to underline the operating condition, match it to NEC 90.3, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["90.3","Article 100"]}'::jsonb);
