INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b21329d1-0d0e-4e0a-aa50-0cb7bb159f31', '38a5b1ac-e91d-491f-b720-75c70d567b19', 11, 'bullet', NULL, 'NEC 90.3 is the first reference to check when Exception Hunting is tested as an enforceable requirement.', 'NEC 90.3 is the first reference to check when Exception Hunting is tested as an enforceable requirement.', '{}'::jsonb);
