INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('46e2aaec-7926-4491-931f-998e6e04a407', '38a5b1ac-e91d-491f-b720-75c70d567b19', 13, 'bullet', NULL, 'The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you. Slow down long enough to confirm the condition before you commit to an answer.', 'The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you. Slow down long enough to confirm the condition before you commit to an answer.', '{}'::jsonb);
