INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d6d3ff29-16cf-4fa7-ba12-3545328cf5a1', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 1, 'paragraph', 'Learning objective', 'Use Timed Code Lookup to develop speed, use index efficiently, practice lookup drills. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Timed Code Lookup to develop speed, use index efficiently, practice lookup drills. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bb95f832-c496-4610-880a-a80c91a34896', '59716e7a-bab8-43b2-9c07-1d2cd724f02e', 2, 'paragraph', 'Why this matters', 'Timed Code Lookup shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Timed Code Lookup shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 100","90.1"]}'::jsonb);
