INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b1ab21f3-c752-4f95-816a-e700e183f6fd', '71144249-a131-40b6-b7ce-33ff65c69919', 1, 'paragraph', 'Learning objective', 'Use Continuous Loads to size for continuous, apply 125% rule, calculate correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Continuous Loads to size for continuous, apply 125% rule, calculate correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["210.20(A)","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f705fdd4-f65b-466c-ac49-29a751ead1c9', '71144249-a131-40b6-b7ce-33ff65c69919', 2, 'paragraph', 'Why this matters', 'Continuous Loads shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Continuous Loads shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["210.20(A)","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('20a08514-b2f4-4292-a2ed-24eca845886a', '71144249-a131-40b6-b7ce-33ff65c69919', 3, 'paragraph', 'Core explanation', 'Continuous Loads covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Continuous Loads covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["210.20(A)","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5723a870-c059-4e36-b805-10ad04aca4aa', '71144249-a131-40b6-b7ce-33ff65c69919', 4, 'paragraph', 'Key concepts', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating continuous loads as vocabulary instead of as an installation or design decision.', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating continuous loads as vocabulary instead of as an installation or design decision.', '{"necReferences":["210.20(A)","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8ad8bc1b-a162-4b39-b31d-006b966cd929', '71144249-a131-40b6-b7ce-33ff65c69919', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 210.20(A) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Continuous Loads, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 210.20(A) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Continuous Loads, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["210.20(A)","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('639da0c4-bc76-4f6c-a0ee-d2136bdbcff3', '71144249-a131-40b6-b7ce-33ff65c69919', 6, 'paragraph', 'Practical example', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["210.20(A)","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('70ed5c95-bb09-4317-addc-9e5bf8e3e6af', '71144249-a131-40b6-b7ce-33ff65c69919', 7, 'paragraph', 'Common mistakes', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["210.20(A)","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('abffd422-ad86-472e-8e2a-a5d60d24841e', '71144249-a131-40b6-b7ce-33ff65c69919', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Continuous Loads inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 210.20(A). The best strategy is to underline the operating condition, match it to NEC 210.20(A), and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Continuous Loads inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 210.20(A). The best strategy is to underline the operating condition, match it to NEC 210.20(A), and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["210.20(A)","210.19(A)"]}'::jsonb);
