INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7076f9a4-1a87-4e97-9b8c-986077d95921', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 1, 'paragraph', 'Learning objective', 'Use Dwelling Circuits to know dwelling circuits, calculate spacing, apply rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Dwelling Circuits to know dwelling circuits, calculate spacing, apply rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["210.11","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ec221340-0f62-40ea-8b3b-046025eae049', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 2, 'paragraph', 'Why this matters', 'Dwelling Circuits shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Dwelling Circuits shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["210.11","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3c9687c6-f91b-4dc9-aabc-bfefa5e7d082', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 3, 'paragraph', 'Core explanation', 'Dwelling Circuits covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Dwelling Circuits covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["210.11","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c5259391-176b-49e8-b0a7-cbb1a11be45b', '0c6b6af9-e148-435c-a9ee-82726bfb398b', 4, 'paragraph', 'Key concepts', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating dwelling circuits as vocabulary instead of as an installation or design decision.', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating dwelling circuits as vocabulary instead of as an installation or design decision.', '{"necReferences":["210.11","210.19(A)"]}'::jsonb);
