INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('868e9d24-5b74-46dd-b7d2-1e7ea3059662', 'ed52a359-658b-433e-bba4-0680bf829ff9', 1, 'paragraph', 'Learning objective', 'Use Multi-Outlet Circuits to understand multi-outlet design, know limitations, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Multi-Outlet Circuits to understand multi-outlet design, know limitations, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["210.23","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6f7b65a5-4f95-4230-a481-b640dc051c49', 'ed52a359-658b-433e-bba4-0680bf829ff9', 2, 'paragraph', 'Why this matters', 'Multi-Outlet Circuits shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Multi-Outlet Circuits shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["210.23","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('138d5b01-5e48-41eb-9d41-39683974912a', 'ed52a359-658b-433e-bba4-0680bf829ff9', 3, 'paragraph', 'Core explanation', 'Multi-Outlet Circuits covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Multi-Outlet Circuits covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["210.23","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a142c7cf-562b-42eb-b9e4-35e6f13af083', 'ed52a359-658b-433e-bba4-0680bf829ff9', 4, 'paragraph', 'Key concepts', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["210.23","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3d8d4d49-835a-4269-af94-ff34d0e83b7d', 'ed52a359-658b-433e-bba4-0680bf829ff9', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 210.23 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Multi-Outlet Circuits, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 210.23 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Multi-Outlet Circuits, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["210.23","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('08e767b4-c107-46db-a527-c31ab4311204', 'ed52a359-658b-433e-bba4-0680bf829ff9', 6, 'paragraph', 'Practical example', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["210.23","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9d715d20-302b-4e55-9106-e801b0ac6dfd', 'ed52a359-658b-433e-bba4-0680bf829ff9', 7, 'paragraph', 'Common mistakes', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. When you review misses, look for the first step where the condition or reference was ignored.', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["210.23","210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('705201e8-ec6d-4569-93c0-97da032da0ac', 'ed52a359-658b-433e-bba4-0680bf829ff9', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Multi-Outlet Circuits inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 210.23 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 210.23, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Multi-Outlet Circuits inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 210.23 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 210.23, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["210.23","210.19(A)"]}'::jsonb);
