INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3b8e0876-59c5-4d80-ba07-8e84a566e116', '599edca8-a3ba-47f1-bff3-09192526a587', 1, 'paragraph', 'Learning objective', 'Use Grounding vs Bonding to distinguish functions, know paths, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Grounding vs Bonding to distinguish functions, know paths, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["250.24","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('832b1b7b-7deb-4458-babe-8f1aefa5bf79', '599edca8-a3ba-47f1-bff3-09192526a587', 2, 'paragraph', 'Why this matters', 'Grounding vs Bonding shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Grounding vs Bonding shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["250.24","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('448bcd25-8e29-45f5-809d-2da2e93893b1', '599edca8-a3ba-47f1-bff3-09192526a587', 3, 'paragraph', 'Core explanation', 'Grounding vs Bonding deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Grounding vs Bonding deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["250.24","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('159af76c-2edd-4885-8954-4787dc2542f7', '599edca8-a3ba-47f1-bff3-09192526a587', 4, 'paragraph', 'Key concepts', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["250.24","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('adc08470-a513-40c2-ab70-e2a8cd4f58fe', '599edca8-a3ba-47f1-bff3-09192526a587', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 250.24 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Grounding vs Bonding, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 250.24 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Grounding vs Bonding, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["250.24","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6c803a37-29a6-4855-827a-b5d21da23660', '599edca8-a3ba-47f1-bff3-09192526a587', 6, 'paragraph', 'Practical example', 'This topic matters when you connect service equipment, feeders, separate buildings, electrodes, and equipment grounding conductors. Good grounding work is deliberate, continuous, and sized to perform under fault conditions rather than by appearance alone. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'This topic matters when you connect service equipment, feeders, separate buildings, electrodes, and equipment grounding conductors. Good grounding work is deliberate, continuous, and sized to perform under fault conditions rather than by appearance alone. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["250.24","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bfc05b71-8190-47ea-8ad0-0fafa90dd958', '599edca8-a3ba-47f1-bff3-09192526a587', 7, 'paragraph', 'Common mistakes', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. When you review misses, look for the first step where the condition or reference was ignored.', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["250.24","250.4"]}'::jsonb);
