INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d31e6739-e97f-4809-869d-0a21692fe6a9', '9c84a57c-b3f5-49e6-bf51-61ca79d78494', 2, 'paragraph', 'Why this matters', 'Grounding Electrodes shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Grounding Electrodes shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["250.50","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bfa2a7a1-2ffb-4aa4-99db-febc6b7f9921', '9c84a57c-b3f5-49e6-bf51-61ca79d78494', 3, 'paragraph', 'Core explanation', 'Grounding Electrodes deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Grounding Electrodes deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["250.50","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7a0c041b-1cac-4727-b0a9-20ba462cb557', '9c84a57c-b3f5-49e6-bf51-61ca79d78494', 4, 'paragraph', 'Key concepts', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["250.50","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1dbd9467-94a4-4ac9-8e61-a58e17db591d', '9c84a57c-b3f5-49e6-bf51-61ca79d78494', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 250.50 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Grounding Electrodes, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 250.50 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Grounding Electrodes, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["250.50","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('60d339eb-7a46-4af1-8278-c41abd36e72b', '9c84a57c-b3f5-49e6-bf51-61ca79d78494', 6, 'paragraph', 'Practical example', 'This topic matters when you connect service equipment, feeders, separate buildings, electrodes, and equipment grounding conductors. Good grounding work is deliberate, continuous, and sized to perform under fault conditions rather than by appearance alone. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'This topic matters when you connect service equipment, feeders, separate buildings, electrodes, and equipment grounding conductors. Good grounding work is deliberate, continuous, and sized to perform under fault conditions rather than by appearance alone. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["250.50","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4618fe67-1a75-4666-9433-69870ff008ca', '9c84a57c-b3f5-49e6-bf51-61ca79d78494', 7, 'paragraph', 'Common mistakes', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["250.50","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3839dce1-6fda-4d70-af9b-7f4d75e15d3b', '9c84a57c-b3f5-49e6-bf51-61ca79d78494', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Grounding Electrodes inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 250.50. The best strategy is to underline the operating condition, match it to NEC 250.50, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Grounding Electrodes inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 250.50. The best strategy is to underline the operating condition, match it to NEC 250.50, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["250.50","250.4"]}'::jsonb);
