INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9476fb13-c49a-4f50-b027-48e6316d6bad', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 1, 'paragraph', 'Learning objective', 'Use Equipment Grounding Sizing to use sizing tables, apply rules, know requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Equipment Grounding Sizing to use sizing tables, apply rules, know requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["250.122","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9db58e47-057e-4bbc-bcfb-c8296a3df5f9', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 2, 'paragraph', 'Why this matters', 'Equipment Grounding Sizing shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Equipment Grounding Sizing shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["250.122","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6eb75c5f-f033-4539-a404-cb433036e2e8', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 3, 'paragraph', 'Core explanation', 'Equipment Grounding Sizing is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Equipment Grounding Sizing is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["250.122","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b96640c8-d14f-483a-bc26-b4d10705cd60', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 4, 'paragraph', 'Key concepts', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["250.122","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('92450c90-6a6a-43ba-ad48-f58a108fe746', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 250.122 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Equipment Grounding Sizing, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 250.122 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Equipment Grounding Sizing, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["250.122","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a1efb3df-ad40-4054-b33f-dc4e8a501788', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 6, 'paragraph', 'Practical example', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["250.122","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c423cad5-3590-4666-a7e8-0c1328746e1c', '5dd5fd2b-e1c8-448e-be2e-5398154861e8', 7, 'paragraph', 'Common mistakes', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["250.122","250.4"]}'::jsonb);
