INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0cef1d35-5731-413b-99f8-66fc64db7f8e', '5783b5fd-1471-49cb-b5cf-2fe1d05e9860', 3, 'paragraph', 'Core explanation', 'Bonding Practices explains the electrical relationship that a working electrician candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Bonding Practices explains the electrical relationship that a working electrician candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["250.24(D)","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('611299bc-4543-4d90-b758-709604b35aca', '5783b5fd-1471-49cb-b5cf-2fe1d05e9860', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["250.24(D)","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('686f63c8-0ba1-4bcb-b2b3-e0e37b23da22', '5783b5fd-1471-49cb-b5cf-2fe1d05e9860', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 250.24(D) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Bonding Practices, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 250.24(D) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Bonding Practices, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["250.24(D)","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b584ef1c-278e-442d-a4b5-52db0f5544e3', '5783b5fd-1471-49cb-b5cf-2fe1d05e9860', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["250.24(D)","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c3aa0717-8495-4f8c-8dc8-827f18aa1ef1', '5783b5fd-1471-49cb-b5cf-2fe1d05e9860', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["250.24(D)","250.4"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('abfa1d9d-39ec-4aec-9291-f7e083d7951c', '5783b5fd-1471-49cb-b5cf-2fe1d05e9860', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Bonding Practices inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 250.24(D). The best strategy is to underline the operating condition, match it to NEC 250.24(D), and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Bonding Practices inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 250.24(D). The best strategy is to underline the operating condition, match it to NEC 250.24(D), and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["250.24(D)","250.4"]}'::jsonb);
