INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7f6e87ce-bcce-448f-bcb1-63f1986b9ea7', 'af9d1c7d-b9d3-49bb-aa4a-d13e22717a15', 1, 'paragraph', 'Learning objective', 'Use Motor Conductors to use motor tables, size conductors, know requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Motor Conductors to use motor tables, size conductors, know requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["430.22","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('25c9f704-5435-4237-a2f0-b300f8ac7b00', 'af9d1c7d-b9d3-49bb-aa4a-d13e22717a15', 2, 'paragraph', 'Why this matters', 'Motor Conductors shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Motor Conductors shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["430.22","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('660db873-e376-4cb8-b08a-40cc8b5d1d73', 'af9d1c7d-b9d3-49bb-aa4a-d13e22717a15', 3, 'paragraph', 'Core explanation', 'Motor Conductors focuses on motor circuits, which are governed by rules that differ from general-purpose branch circuits. The exam usually tests whether you know which value comes from nameplate data and which value must come from the NEC tables. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Motor Conductors focuses on motor circuits, which are governed by rules that differ from general-purpose branch circuits. The exam usually tests whether you know which value comes from nameplate data and which value must come from the NEC tables. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["430.22","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('71fd14f8-b000-4219-844e-c0c2ec207bbc', 'af9d1c7d-b9d3-49bb-aa4a-d13e22717a15', 4, 'paragraph', 'Key concepts', 'Keep conductor sizing, overload protection, and short-circuit or ground-fault protection in separate buckets. They work together, but they are not selected by the same rule or the same multiplier. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Keep conductor sizing, overload protection, and short-circuit or ground-fault protection in separate buckets. They work together, but they are not selected by the same rule or the same multiplier. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["430.22","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('79a5ab64-66a4-4ff2-868f-0b538d94b32a', 'af9d1c7d-b9d3-49bb-aa4a-d13e22717a15', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 430.22 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Motor Conductors, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 430.22 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Motor Conductors, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["430.22","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6ab8934c-3be6-4ddd-9a88-0f6f5d801cb8', 'af9d1c7d-b9d3-49bb-aa4a-d13e22717a15', 6, 'paragraph', 'Practical example', 'In the field, this topic matters any time a motor starts, runs, trips, overheats, or needs a controller and protective device package. Good motor work begins with the correct full-load current reference and ends with coordinated protection. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'In the field, this topic matters any time a motor starts, runs, trips, overheats, or needs a controller and protective device package. Good motor work begins with the correct full-load current reference and ends with coordinated protection. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["430.22","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5d682a72-9691-4148-be59-92fda1e53901', 'af9d1c7d-b9d3-49bb-aa4a-d13e22717a15', 7, 'paragraph', 'Common mistakes', 'Candidates often size every motor component from one number and forget that the code uses different rules for conductors, overloads, and branch-circuit protection. Another common miss is confusing horsepower tables with actual nameplate information. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'Candidates often size every motor component from one number and forget that the code uses different rules for conductors, overloads, and branch-circuit protection. Another common miss is confusing horsepower tables with actual nameplate information. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["430.22","430.52"]}'::jsonb);
