INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7817d74c-aeef-4799-85ad-b3cebcff1b72', '34f83032-e5c2-4b7c-b640-bb632dc92efe', 2, 'paragraph', 'Why this matters', 'Motor Protection shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Motor Protection shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('52576a61-7285-40d5-8ad6-0ae3e2487315', '34f83032-e5c2-4b7c-b640-bb632dc92efe', 3, 'paragraph', 'Core explanation', 'Motor Protection focuses on motor circuits, which are governed by rules that differ from general-purpose branch circuits. The exam usually tests whether you know which value comes from nameplate data and which value must come from the NEC tables. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Motor Protection focuses on motor circuits, which are governed by rules that differ from general-purpose branch circuits. The exam usually tests whether you know which value comes from nameplate data and which value must come from the NEC tables. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["430.52"]}'::jsonb);
