INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d0c7ad03-5193-43d0-a25b-1a46f7f1616e', '34f83032-e5c2-4b7c-b640-bb632dc92efe', 6, 'paragraph', 'Practical example', 'In the field, this topic matters any time a motor starts, runs, trips, overheats, or needs a controller and protective device package. Good motor work begins with the correct full-load current reference and ends with coordinated protection. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'In the field, this topic matters any time a motor starts, runs, trips, overheats, or needs a controller and protective device package. Good motor work begins with the correct full-load current reference and ends with coordinated protection. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2f0faf1f-607f-465f-937f-8079e5d5cf4c', '34f83032-e5c2-4b7c-b640-bb632dc92efe', 7, 'paragraph', 'Common mistakes', 'Candidates often size every motor component from one number and forget that the code uses different rules for conductors, overloads, and branch-circuit protection. Another common miss is confusing horsepower tables with actual nameplate information. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates often size every motor component from one number and forget that the code uses different rules for conductors, overloads, and branch-circuit protection. Another common miss is confusing horsepower tables with actual nameplate information. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2ba80328-74fb-4fd8-b6ca-d0134ceefe35', '34f83032-e5c2-4b7c-b640-bb632dc92efe', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Motor Protection inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 430.52. The best strategy is to underline the operating condition, match it to NEC 430.52, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Motor Protection inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 430.52. The best strategy is to underline the operating condition, match it to NEC 430.52, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["430.52"]}'::jsonb);
