INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9233ab3e-7662-407e-8631-28ad8dad6217', '34f83032-e5c2-4b7c-b640-bb632dc92efe', 13, 'bullet', NULL, 'The misconception to avoid is treating motor protection as vocabulary instead of as an installation or design decision. Slow down long enough to confirm the condition before you commit to an answer.', 'The misconception to avoid is treating motor protection as vocabulary instead of as an installation or design decision. Slow down long enough to confirm the condition before you commit to an answer.', '{}'::jsonb);
