INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1c8c5cbe-9a1d-41a1-9f88-b4334cb1d3be', '85ad02ca-1fdd-4b7e-a5cc-0f06fd57641e', 1, 'paragraph', 'Learning objective', 'Use Motor Disconnects to know disconnect rules, understand location, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Motor Disconnects to know disconnect rules, understand location, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["430.74","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('32547a0f-1b29-422f-8654-5cc173d59429', '85ad02ca-1fdd-4b7e-a5cc-0f06fd57641e', 2, 'paragraph', 'Why this matters', 'Motor Disconnects shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Motor Disconnects shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["430.74","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a921c71c-1244-4af1-aab3-667e7bad0d07', '85ad02ca-1fdd-4b7e-a5cc-0f06fd57641e', 3, 'paragraph', 'Core explanation', 'Motor Disconnects teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Motor Disconnects teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["430.74","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c78d7863-67ce-4a3d-8b43-4f12de15eb54', '85ad02ca-1fdd-4b7e-a5cc-0f06fd57641e', 4, 'paragraph', 'Key concepts', 'Use code words carefully. Terms such as permitted, required, identified, listed, labeled, and approved are not interchangeable, and exam writers rely on those distinctions when they build distractors. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Use code words carefully. Terms such as permitted, required, identified, listed, labeled, and approved are not interchangeable, and exam writers rely on those distinctions when they build distractors. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["430.74","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('55c82422-960a-4653-ba5c-6c50ccf1d5c2', '85ad02ca-1fdd-4b7e-a5cc-0f06fd57641e', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 430.74 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Motor Disconnects, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 430.74 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Motor Disconnects, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["430.74","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('caa5bc2c-47eb-4458-bce0-9f22c45ed889', '85ad02ca-1fdd-4b7e-a5cc-0f06fd57641e', 6, 'paragraph', 'Practical example', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["430.74","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9ed0d160-f794-4523-ac8b-5ed5588eb461', '85ad02ca-1fdd-4b7e-a5cc-0f06fd57641e', 7, 'paragraph', 'Common mistakes', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. When you review misses, look for the first step where the condition or reference was ignored.', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["430.74","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('73d8d29f-1482-4f6d-abb1-0ef66faef5ab', '85ad02ca-1fdd-4b7e-a5cc-0f06fd57641e', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Motor Disconnects inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 430.74 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 430.74, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Motor Disconnects inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 430.74 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 430.74, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["430.74","430.52"]}'::jsonb);
