INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('37515a31-079d-48cc-b5c0-aa07ce8773a4', 'a28ad046-6c2d-48ed-847a-0cbc444e2562', 1, 'paragraph', 'Learning objective', 'Use Multi-Motor Circuits to design multi-motor, size correctly, apply rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Multi-Motor Circuits to design multi-motor, size correctly, apply rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["430.22(B)","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('07352320-7720-4775-a7e1-b0211b33e538', 'a28ad046-6c2d-48ed-847a-0cbc444e2562', 2, 'paragraph', 'Why this matters', 'Multi-Motor Circuits shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Multi-Motor Circuits shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["430.22(B)","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('efff62cf-8081-4ad5-a445-5e677368a2f6', 'a28ad046-6c2d-48ed-847a-0cbc444e2562', 3, 'paragraph', 'Core explanation', 'Multi-Motor Circuits focuses on motor circuits, which are governed by rules that differ from general-purpose branch circuits. The exam usually tests whether you know which value comes from nameplate data and which value must come from the NEC tables. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Multi-Motor Circuits focuses on motor circuits, which are governed by rules that differ from general-purpose branch circuits. The exam usually tests whether you know which value comes from nameplate data and which value must come from the NEC tables. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["430.22(B)","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6bd9f063-22bf-4ee7-923b-13fd510db846', 'a28ad046-6c2d-48ed-847a-0cbc444e2562', 4, 'paragraph', 'Key concepts', 'Keep conductor sizing, overload protection, and short-circuit or ground-fault protection in separate buckets. They work together, but they are not selected by the same rule or the same multiplier. The misconception to avoid is treating multi-motor circuits as vocabulary instead of as an installation or design decision.', 'Keep conductor sizing, overload protection, and short-circuit or ground-fault protection in separate buckets. They work together, but they are not selected by the same rule or the same multiplier. The misconception to avoid is treating multi-motor circuits as vocabulary instead of as an installation or design decision.', '{"necReferences":["430.22(B)","430.52"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('189b52a7-d564-47e1-876c-8ffdfa88eeec', 'a28ad046-6c2d-48ed-847a-0cbc444e2562', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 430.22(B) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Multi-Motor Circuits, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 430.22(B) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Multi-Motor Circuits, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["430.22(B)","430.52"]}'::jsonb);
