INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2752e8c1-1409-4ca5-a63d-30ecfba1d683', 'c6a48e26-ba9d-4b38-89fe-2c38e22b3e5f', 1, 'paragraph', 'Learning objective', 'Use Service Components to know components, understand layout, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Service Components to know components, understand layout, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["230.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('348f9162-5327-47f4-8def-915006e0e63d', 'c6a48e26-ba9d-4b38-89fe-2c38e22b3e5f', 2, 'paragraph', 'Why this matters', 'Service Components shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Service Components shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["230.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('58a62f0f-3116-4905-a36c-b80f78669df3', 'c6a48e26-ba9d-4b38-89fe-2c38e22b3e5f', 3, 'paragraph', 'Core explanation', 'Service Components is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Service Components is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["230.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d8ab928c-bfbe-4375-be25-abb70c917be9', 'c6a48e26-ba9d-4b38-89fe-2c38e22b3e5f', 4, 'paragraph', 'Key concepts', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["230.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3d270196-2561-4f71-99b2-e80b7a742d10', 'c6a48e26-ba9d-4b38-89fe-2c38e22b3e5f', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 230.2 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Service Components, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 230.2 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Service Components, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["230.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b4305c29-09b1-49d4-8225-1ad121b71968', 'c6a48e26-ba9d-4b38-89fe-2c38e22b3e5f', 6, 'paragraph', 'Practical example', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["230.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('df9cf8a0-7614-401f-9815-4d3bef75a006', 'c6a48e26-ba9d-4b38-89fe-2c38e22b3e5f', 7, 'paragraph', 'Common mistakes', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["230.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7a28fc63-3436-4263-b7ec-8f92869fca53', 'c6a48e26-ba9d-4b38-89fe-2c38e22b3e5f', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Service Components inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 230.2 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 230.2, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Service Components inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 230.2 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 230.2, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["230.2","90.1"]}'::jsonb);
