INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('eee698a5-69cf-4309-945d-e8c1050edc84', '416fdf02-ee90-44dc-8447-f8be65171506', 2, 'paragraph', 'Why this matters', 'Feeder Sizing shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Feeder Sizing shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["215.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('399724a3-c677-49f0-a9d3-95a1476ce4eb', '416fdf02-ee90-44dc-8447-f8be65171506', 3, 'paragraph', 'Core explanation', 'Feeder Sizing is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Feeder Sizing is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["215.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('58bcaddf-8134-4816-958e-c29f8d9b6f06', '416fdf02-ee90-44dc-8447-f8be65171506', 4, 'paragraph', 'Key concepts', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["215.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8f83343b-a33a-404e-b843-190b58860d2d', '416fdf02-ee90-44dc-8447-f8be65171506', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 215.2 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Feeder Sizing, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 215.2 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Feeder Sizing, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["215.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a307e897-f2bf-4d6e-9784-c438f8f6cb8d', '416fdf02-ee90-44dc-8447-f8be65171506', 6, 'paragraph', 'Practical example', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["215.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c645f713-c0fc-4d11-9b85-1350714dcdf2', '416fdf02-ee90-44dc-8447-f8be65171506', 7, 'paragraph', 'Common mistakes', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["215.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('79bb00d9-6596-4ab7-bea0-05adf8529f8b', '416fdf02-ee90-44dc-8447-f8be65171506', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Feeder Sizing inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 215.2. The best strategy is to underline the operating condition, match it to NEC 215.2, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Feeder Sizing inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 215.2. The best strategy is to underline the operating condition, match it to NEC 215.2, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["215.2","90.1"]}'::jsonb);
