INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('127806ce-d70d-4968-a2d3-4eae1dbdd72b', '5fc5791b-6052-4abf-b927-44156697a5d0', 2, 'paragraph', 'Why this matters', 'Temperature Adjustment shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Temperature Adjustment shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["310.15(B)","310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('be78476d-63a9-40fe-87eb-53ee1546165c', '5fc5791b-6052-4abf-b927-44156697a5d0', 3, 'paragraph', 'Core explanation', 'Temperature Adjustment is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Temperature Adjustment is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["310.15(B)","310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a2affb78-4d67-496c-99cf-bae99295d5d1', '5fc5791b-6052-4abf-b927-44156697a5d0', 4, 'paragraph', 'Key concepts', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["310.15(B)","310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('df95f099-1b53-4c84-b5f7-9cdb6a70d766', '5fc5791b-6052-4abf-b927-44156697a5d0', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 310.15(B) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Temperature Adjustment, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 310.15(B) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Temperature Adjustment, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["310.15(B)","310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5f1af801-7cb0-46cc-b32e-2e5a25a0aec9', '5fc5791b-6052-4abf-b927-44156697a5d0', 6, 'paragraph', 'Practical example', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["310.15(B)","310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b441793f-5ca9-495d-83fb-ee7891550088', '5fc5791b-6052-4abf-b927-44156697a5d0', 7, 'paragraph', 'Common mistakes', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["310.15(B)","310.14"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4f228d88-2880-426b-a7a5-0468b147eed1', '5fc5791b-6052-4abf-b927-44156697a5d0', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Temperature Adjustment inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 310.15(B) treats as decisive. The best strategy is to underline the operating condition, match it to NEC 310.15(B), and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Temperature Adjustment inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 310.15(B) treats as decisive. The best strategy is to underline the operating condition, match it to NEC 310.15(B), and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["310.15(B)","310.14"]}'::jsonb);
