INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('05ff1b55-e734-472d-a783-746a2f16f79a', '33f4d5a8-c50b-4b58-95bb-c2496d2264f7', 4, 'paragraph', 'Key concepts', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["Article 450","90.1"]}'::jsonb);
