INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('52f4c29b-dfe0-4475-8768-9974a943fc7d', '33f4d5a8-c50b-4b58-95bb-c2496d2264f7', 6, 'paragraph', 'Practical example', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["Article 450","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('315f46d4-20b4-4b00-98df-e545f123d86e', '33f4d5a8-c50b-4b58-95bb-c2496d2264f7', 7, 'paragraph', 'Common mistakes', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["Article 450","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b5fe6f02-41b7-4f2a-bb17-349d86df49cd', '33f4d5a8-c50b-4b58-95bb-c2496d2264f7', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Transformer Basics inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC Article 450. The best strategy is to underline the operating condition, match it to NEC Article 450, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Transformer Basics inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC Article 450. The best strategy is to underline the operating condition, match it to NEC Article 450, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 450","90.1"]}'::jsonb);
