INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f895d21a-4710-4b0f-abce-c5ef3f7796e4', '156e1c46-9056-4591-bbe0-36a9cb68dea5', 1, 'paragraph', 'Learning objective', 'Use Transformer Protection to size protection, understand rules, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Transformer Protection to size protection, understand rules, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["450.3","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f8128950-8cff-4294-9960-8cf04fed7b0f', '156e1c46-9056-4591-bbe0-36a9cb68dea5', 2, 'paragraph', 'Why this matters', 'Transformer Protection shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Transformer Protection shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["450.3","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('500c4904-43d6-4ac2-8977-8778edec3971', '156e1c46-9056-4591-bbe0-36a9cb68dea5', 3, 'paragraph', 'Core explanation', 'Transformer Protection combines code knowledge with practical field judgment. A strong answer shows that you understand both the purpose of the rule and the installation decision that follows from it. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Transformer Protection combines code knowledge with practical field judgment. A strong answer shows that you understand both the purpose of the rule and the installation decision that follows from it. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["450.3","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ed386c7c-7bed-4e2f-843a-064ef400eb95', '156e1c46-9056-4591-bbe0-36a9cb68dea5', 4, 'paragraph', 'Key concepts', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The misconception to avoid is treating transformer protection as vocabulary instead of as an installation or design decision.', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The misconception to avoid is treating transformer protection as vocabulary instead of as an installation or design decision.', '{"necReferences":["450.3","90.1"]}'::jsonb);
