INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('379e6a3d-4dcc-4673-a712-317376a1ffe0', '156e1c46-9056-4591-bbe0-36a9cb68dea5', 7, 'paragraph', 'Common mistakes', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["450.3","90.1"]}'::jsonb);
