INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('548396ae-bcdc-48d3-b2db-2b884ecdb8c4', '5e5c233a-8a1f-4278-ab67-957a1337258d', 13, 'bullet', NULL, 'The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you. Slow down long enough to confirm the condition before you commit to an answer.', 'The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you. Slow down long enough to confirm the condition before you commit to an answer.', '{}'::jsonb);
