INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a0754dde-3c14-4727-9c33-182cf9e53259', '0f85d0cf-2b7d-4e61-b36a-20e8528757e5', 1, 'paragraph', 'Learning objective', 'Use Fault Currents to calculate fault current, understand ratings, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Fault Currents to calculate fault current, understand ratings, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["110.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('edd6aa8d-d6b2-46ea-bf76-8596d7b024d7', '0f85d0cf-2b7d-4e61-b36a-20e8528757e5', 2, 'paragraph', 'Why this matters', 'Fault Currents shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Fault Currents shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["110.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('179c51e0-3621-44bc-9081-ececaa6b1330', '0f85d0cf-2b7d-4e61-b36a-20e8528757e5', 3, 'paragraph', 'Core explanation', 'Fault Currents explains the electrical relationship that a working electrician candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Fault Currents explains the electrical relationship that a working electrician candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["110.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('110837cc-6ea5-4c44-92fa-c97021c89008', '0f85d0cf-2b7d-4e61-b36a-20e8528757e5', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["110.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8a55f32a-14fe-48cd-967b-5f36cda67301', '0f85d0cf-2b7d-4e61-b36a-20e8528757e5', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 110.20 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Fault Currents, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 110.20 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Fault Currents, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["110.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8415b5a5-2ef5-421c-a656-f87c4a98fa74', '0f85d0cf-2b7d-4e61-b36a-20e8528757e5', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["110.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c9cc9067-a5ce-4637-81cb-873cca51156f', '0f85d0cf-2b7d-4e61-b36a-20e8528757e5', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["110.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fda49dfc-addb-4f38-8508-2152cfe92f21', '0f85d0cf-2b7d-4e61-b36a-20e8528757e5', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Fault Currents inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 110.20 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 110.20, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Fault Currents inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 110.20 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 110.20, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["110.20","90.1"]}'::jsonb);
