INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a12631ff-da36-4f42-9b2a-ab74466e3354', '624ba545-9f42-4c08-82d7-f37e56ffbbdd', 1, 'paragraph', 'Learning objective', 'Use Conduit Fill to use tables, calculate fill, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Conduit Fill to use tables, calculate fill, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Chapter 3","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('cb297224-c03e-475a-b90a-c252a254c33c', '624ba545-9f42-4c08-82d7-f37e56ffbbdd', 2, 'paragraph', 'Why this matters', 'Conduit Fill shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Conduit Fill shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Chapter 3","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1842b584-66c8-43f1-8b79-41dcb4d5058c', '624ba545-9f42-4c08-82d7-f37e56ffbbdd', 3, 'paragraph', 'Core explanation', 'Conduit Fill covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Conduit Fill covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["Chapter 3","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e483904a-612e-420b-a0f5-bd603e879294', '624ba545-9f42-4c08-82d7-f37e56ffbbdd', 4, 'paragraph', 'Key concepts', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating conduit fill as vocabulary instead of as an installation or design decision.', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating conduit fill as vocabulary instead of as an installation or design decision.', '{"necReferences":["Chapter 3","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8886f587-b10e-48f9-a268-c8b45964ad01', '624ba545-9f42-4c08-82d7-f37e56ffbbdd', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Chapter 3 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Conduit Fill, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Chapter 3 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Conduit Fill, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Chapter 3","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fc610ddb-abe3-4a6b-9dfa-115d18869e0f', '624ba545-9f42-4c08-82d7-f37e56ffbbdd', 6, 'paragraph', 'Practical example', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["Chapter 3","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e42ee76b-e9cc-434e-afe5-5a3e7706e03f', '624ba545-9f42-4c08-82d7-f37e56ffbbdd', 7, 'paragraph', 'Common mistakes', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["Chapter 3","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c06df7e0-0f72-4327-923f-b51a39418659', '624ba545-9f42-4c08-82d7-f37e56ffbbdd', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Conduit Fill inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Chapter 3. The best strategy is to underline the operating condition, match it to NEC Chapter 3, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Conduit Fill inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Chapter 3. The best strategy is to underline the operating condition, match it to NEC Chapter 3, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Chapter 3","90.1"]}'::jsonb);
