INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('943ef33d-b8c4-4fa3-994a-e9b93f8901b5', 'f56b03e0-2eb0-48f2-b7f8-b362b2882026', 1, 'paragraph', 'Learning objective', 'Use Cable Support to know support rules, apply spacing, understand methods. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Cable Support to know support rules, apply spacing, understand methods. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('52abedee-a073-4599-81e5-f5513f8a8a38', 'f56b03e0-2eb0-48f2-b7f8-b362b2882026', 2, 'paragraph', 'Why this matters', 'Cable Support shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Cable Support shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f6262c3c-a0a2-41c8-85bc-9e52aceb2b56', 'f56b03e0-2eb0-48f2-b7f8-b362b2882026', 3, 'paragraph', 'Core explanation', 'Cable Support covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Cable Support covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5ae200fe-a50b-4a74-a2ec-5cffdef069ff', 'f56b03e0-2eb0-48f2-b7f8-b362b2882026', 4, 'paragraph', 'Key concepts', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9b5a85f5-460c-4388-8a5a-92fccff16863', 'f56b03e0-2eb0-48f2-b7f8-b362b2882026', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 300.11 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Cable Support, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 300.11 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Cable Support, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0d153c6a-f2d3-4461-ba1d-60651a746c59', 'f56b03e0-2eb0-48f2-b7f8-b362b2882026', 6, 'paragraph', 'Practical example', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('542f1586-f1c9-4864-9e29-dec689abef11', 'f56b03e0-2eb0-48f2-b7f8-b362b2882026', 7, 'paragraph', 'Common mistakes', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. When you review misses, look for the first step where the condition or reference was ignored.', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["300.11"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4e418908-21e1-49d2-a659-658dcf1000e1', 'f56b03e0-2eb0-48f2-b7f8-b362b2882026', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Cable Support inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 300.11 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 300.11, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Cable Support inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 300.11 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 300.11, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["300.11"]}'::jsonb);
