INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('dafc9035-a851-4103-8185-fdd23d36130f', 'af4c4af3-368f-420e-a36d-4dcea98ebd0d', 2, 'paragraph', 'Why this matters', 'Cable Tray Systems shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Cable Tray Systems shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 392","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0138edac-68d3-45f7-b0a8-2a8a1eb80567', 'af4c4af3-368f-420e-a36d-4dcea98ebd0d', 3, 'paragraph', 'Core explanation', 'Cable Tray Systems covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Cable Tray Systems covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["Article 392","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0e7365ba-fb3f-4210-b567-a25816aebf65', 'af4c4af3-368f-420e-a36d-4dcea98ebd0d', 4, 'paragraph', 'Key concepts', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating cable tray systems as vocabulary instead of as an installation or design decision.', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating cable tray systems as vocabulary instead of as an installation or design decision.', '{"necReferences":["Article 392","90.1"]}'::jsonb);
