INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e9e89405-c193-4a7b-a61b-c756878de98d', 'af4c4af3-368f-420e-a36d-4dcea98ebd0d', 6, 'paragraph', 'Practical example', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["Article 392","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('60788b6c-2e4b-4b14-b30e-7cc5c2c97f9e', 'af4c4af3-368f-420e-a36d-4dcea98ebd0d', 7, 'paragraph', 'Common mistakes', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["Article 392","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('606596c3-d03d-4f8e-a2ce-96d65207ba26', 'af4c4af3-368f-420e-a36d-4dcea98ebd0d', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Cable Tray Systems inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 392. The best strategy is to underline the operating condition, match it to NEC Article 392, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Cable Tray Systems inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 392. The best strategy is to underline the operating condition, match it to NEC Article 392, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 392","90.1"]}'::jsonb);
