INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4ea66d95-7054-4897-95a8-604879151edd', 'f396466e-38b5-40d3-bce5-3e3c020ea6be', 1, 'paragraph', 'Learning objective', 'Use Voltage Drop Calculations to calculate voltage drop, apply limits, size conductors. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Voltage Drop Calculations to calculate voltage drop, apply limits, size conductors. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d9ae5cec-85e0-4895-a6e5-b5ac6198b54d', 'f396466e-38b5-40d3-bce5-3e3c020ea6be', 2, 'paragraph', 'Why this matters', 'Voltage Drop Calculations shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Voltage Drop Calculations shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('19a98f85-92be-49bc-9d35-510369eebd2f', 'f396466e-38b5-40d3-bce5-3e3c020ea6be', 3, 'paragraph', 'Core explanation', 'Voltage Drop Calculations explains the electrical relationship that a working electrician candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Voltage Drop Calculations explains the electrical relationship that a working electrician candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c13e57f2-2742-4e5b-9782-bb6e7eff277b', 'f396466e-38b5-40d3-bce5-3e3c020ea6be', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The misconception to avoid is treating voltage drop calculations as vocabulary instead of as an installation or design decision.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The misconception to avoid is treating voltage drop calculations as vocabulary instead of as an installation or design decision.', '{"necReferences":["210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('dee847bc-252f-4c72-8d0f-3e8e360875d4', 'f396466e-38b5-40d3-bce5-3e3c020ea6be', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 210.19(A) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Voltage Drop Calculations, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 210.19(A) and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Voltage Drop Calculations, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1d0d81c0-ae82-4eb6-8a3e-f68b3e5730ce', 'f396466e-38b5-40d3-bce5-3e3c020ea6be', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5631aabd-d63c-44cc-b2fe-7147fac764e1', 'f396466e-38b5-40d3-bce5-3e3c020ea6be', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["210.19(A)"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2cc112d4-7460-4790-93cd-7480521ca22c', 'f396466e-38b5-40d3-bce5-3e3c020ea6be', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Voltage Drop Calculations inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 210.19(A). The best strategy is to underline the operating condition, match it to NEC 210.19(A), and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Voltage Drop Calculations inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 210.19(A). The best strategy is to underline the operating condition, match it to NEC 210.19(A), and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["210.19(A)"]}'::jsonb);
