INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4aff55af-4e96-483c-86f4-14f4719abdab', 'f396466e-38b5-40d3-bce5-3e3c020ea6be', 13, 'bullet', NULL, 'The misconception to avoid is treating voltage drop calculations as vocabulary instead of as an installation or design decision. Slow down long enough to confirm the condition before you commit to an answer.', 'The misconception to avoid is treating voltage drop calculations as vocabulary instead of as an installation or design decision. Slow down long enough to confirm the condition before you commit to an answer.', '{}'::jsonb);
