INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('cf069e21-65ee-4cbb-8a6e-86cac06c5e7a', '65881a0a-b251-4b73-8fea-c9603c3ff136', 1, 'paragraph', 'Learning objective', 'Use Conduit Types and Applications to know conduit types, understand uses, apply rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Conduit Types and Applications to know conduit types, understand uses, apply rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 356","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8ec73045-58a5-4bd5-b60f-258424bdc7ce', '65881a0a-b251-4b73-8fea-c9603c3ff136', 2, 'paragraph', 'Why this matters', 'Conduit Types and Applications shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Conduit Types and Applications shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 356","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e65d4db9-d26f-4f86-80da-52f139670f78', '65881a0a-b251-4b73-8fea-c9603c3ff136', 3, 'paragraph', 'Core explanation', 'Conduit Types and Applications covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Conduit Types and Applications covers how equipment or wiring is installed so that the finished work is secure, serviceable, and safe. The exam usually tests whether you can match the wiring method, support rule, or equipment use requirement to the actual installation condition. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["Article 356","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a9684a0d-560d-43f2-b11a-c4a4b19ef40c', '65881a0a-b251-4b73-8fea-c9603c3ff136', 4, 'paragraph', 'Key concepts', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating conduit types and applications as vocabulary instead of as an installation or design decision.', 'Look for three things every time: the environment, the method, and the termination. If one of those changes, the correct answer often changes with it. The misconception to avoid is treating conduit types and applications as vocabulary instead of as an installation or design decision.', '{"necReferences":["Article 356","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('54414fd8-bedf-4d75-88e5-3ea8eb4eaee9', '65881a0a-b251-4b73-8fea-c9603c3ff136', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 356 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Conduit Types and Applications, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 356 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Conduit Types and Applications, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 356","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('eba85bc9-249e-4939-a289-be810fe2067a', '65881a0a-b251-4b73-8fea-c9603c3ff136', 6, 'paragraph', 'Practical example', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'This shows up when you choose raceway, cable, boxes, fittings, or device locations in a real build. A correct installation is not just physically possible; it also has to follow listing instructions, support rules, and spacing requirements. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["Article 356","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('076c12f5-fc73-49e5-9bfb-0461956e202a', '65881a0a-b251-4b73-8fea-c9603c3ff136', 7, 'paragraph', 'Common mistakes', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates lose points by assuming all wiring methods are interchangeable or by overlooking support, fill, termination, or location limits. The safest exam habit is to ask what is permitted here, what is prohibited here, and what condition changed the answer. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["Article 356","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('adddb364-d798-4d47-9701-01e2cbe53f31', '65881a0a-b251-4b73-8fea-c9603c3ff136', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Conduit Types and Applications inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 356. The best strategy is to underline the operating condition, match it to NEC Article 356, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Conduit Types and Applications inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 356. The best strategy is to underline the operating condition, match it to NEC Article 356, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 356","90.1"]}'::jsonb);
