INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('27141535-34c9-4b09-826f-45ca2b488ff3', '8d165d0d-1a39-4d7b-9019-067b449c6280', 2, 'paragraph', 'Why this matters', 'Raceways in Hazardous Locations shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Raceways in Hazardous Locations shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["500-505","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2f7433af-80b1-42e6-9323-a6b3d3db8f10', '8d165d0d-1a39-4d7b-9019-067b449c6280', 3, 'paragraph', 'Core explanation', 'Raceways in Hazardous Locations explains the electrical relationship that a working electrician candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Raceways in Hazardous Locations explains the electrical relationship that a working electrician candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["500-505","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8f3c7467-0e6c-49d7-985f-43b32e879e47', '8d165d0d-1a39-4d7b-9019-067b449c6280', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["500-505","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6216c7c8-d344-4cee-9e4c-12d8dedc85fe', '8d165d0d-1a39-4d7b-9019-067b449c6280', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 500-505 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Raceways in Hazardous Locations, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 500-505 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Raceways in Hazardous Locations, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["500-505","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('14cff5f8-5716-43fd-8a2a-cbd0cb023857', '8d165d0d-1a39-4d7b-9019-067b449c6280', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["500-505","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('20a05457-4cff-4840-90dd-2e91c6892768', '8d165d0d-1a39-4d7b-9019-067b449c6280', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["500-505","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bcf4d06a-90fa-4ee8-96c3-8a2e5629ab31', '8d165d0d-1a39-4d7b-9019-067b449c6280', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Raceways in Hazardous Locations inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 500-505. The best strategy is to underline the operating condition, match it to NEC 500-505, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Raceways in Hazardous Locations inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 500-505. The best strategy is to underline the operating condition, match it to NEC 500-505, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["500-505","90.1"]}'::jsonb);
