INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('aaa7d188-9490-4edf-866d-d92b0781bdae', '8d165d0d-1a39-4d7b-9019-067b449c6280', 13, 'bullet', NULL, 'The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you. Slow down long enough to confirm the condition before you commit to an answer.', 'The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you. Slow down long enough to confirm the condition before you commit to an answer.', '{}'::jsonb);
