INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ec207dc9-7366-4ca3-8fa1-34eeb89540d3', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 1, 'paragraph', 'Learning objective', 'Use Service Design Workflow to design complete systems, understand hierarchy, apply all rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Service Design Workflow to design complete systems, understand hierarchy, apply all rules. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f888e5bf-2a46-488d-89cb-37dcd7c46990', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 2, 'paragraph', 'Why this matters', 'Service Design Workflow shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Service Design Workflow shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a0e4eb4d-516b-4d26-9370-82b9ce282537', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 3, 'paragraph', 'Core explanation', 'Service Design Workflow is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Service Design Workflow is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('cdb5033e-9f2a-411b-9f3d-01510bb0256a', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 4, 'paragraph', 'Key concepts', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6a739d73-21bd-4d2a-bbca-f6ef616d8bd1', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 220.40 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Service Design Workflow, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 220.40 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Service Design Workflow, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7265f527-a984-4047-9e7d-82c2979b5f36', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 6, 'paragraph', 'Practical example', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4eaaca2d-0d8c-4ca0-a336-194c64627920', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 7, 'paragraph', 'Common mistakes', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5c6c2a45-e7ab-490b-ba04-e3cf92bf524f', 'a54341a4-d901-4ad6-8a4b-a2a943a71bd4', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Service Design Workflow inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 220.40 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 220.40, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Service Design Workflow inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 220.40 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 220.40, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["220.40"]}'::jsonb);
