INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0a98d759-1513-4771-9bb9-541b0db6771d', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 2, 'paragraph', 'Why this matters', 'Using Tables and Exceptions shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Using Tables and Exceptions shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["220.42","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('06275340-66a4-428b-8523-5495fa3e0b0e', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 3, 'paragraph', 'Core explanation', 'Using Tables and Exceptions combines code knowledge with practical field judgment. A strong answer shows that you understand both the purpose of the rule and the installation decision that follows from it. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Using Tables and Exceptions combines code knowledge with practical field judgment. A strong answer shows that you understand both the purpose of the rule and the installation decision that follows from it. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["220.42","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bf91127a-0bc5-4ca8-a0da-0297bb4eb44d', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 4, 'paragraph', 'Key concepts', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["220.42","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('25140c51-1f5a-4635-9fc0-c2a2da96e85f', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 220.42 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Using Tables and Exceptions, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 220.42 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Using Tables and Exceptions, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["220.42","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bd9c5ad0-5d21-4bd0-92aa-f783dcf7629d', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 6, 'paragraph', 'Practical example', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["220.42","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a2e9cd4d-1d74-4193-81e3-9e010c3b34bc', '0f92cda0-eff0-42b8-bcb2-1bea9d0f13bc', 7, 'paragraph', 'Common mistakes', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. When you review misses, look for the first step where the condition or reference was ignored.', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["220.42","220.40"]}'::jsonb);
