INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d1984a26-d7ad-4779-bd9d-773de0262afa', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 2, 'paragraph', 'Why this matters', 'Demand Factor Applications shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Demand Factor Applications shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('76d61431-bb28-4f9b-9c2f-0d6259a56015', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 3, 'paragraph', 'Core explanation', 'Demand Factor Applications explains the electrical relationship that a supervisory and design-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Demand Factor Applications explains the electrical relationship that a supervisory and design-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('53084514-6b7b-42a7-8ae4-de1999b759fd', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('aee99b86-c53a-44b1-a40a-10f33c6515ea', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 220.40 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Demand Factor Applications, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 220.40 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Demand Factor Applications, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b3934628-462d-4358-9788-db8a368743b4', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8f96c106-f08d-4f99-8dcc-f042bdfa5e2f', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('886f1e63-f0da-4aae-adee-f49ee1247f0c', 'fa82e6c5-799d-4610-a465-cdf06f82724b', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Demand Factor Applications inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 220.40 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 220.40, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Demand Factor Applications inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 220.40 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 220.40, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["220.40"]}'::jsonb);
