INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3d27f99c-ba5b-4a67-ace6-9f305a235a33', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 2, 'paragraph', 'Why this matters', 'Diversity vs Demand shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Diversity vs Demand shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["215.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0932ff5f-82b8-4a3c-b41f-7b9b35198be7', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 3, 'paragraph', 'Core explanation', 'Diversity vs Demand is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Diversity vs Demand is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["215.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fe127af7-6254-48b0-a913-26a390e0a846', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 4, 'paragraph', 'Key concepts', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["215.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bae6b79e-d251-4cdb-8545-de680826cd75', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 215.2 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Diversity vs Demand, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 215.2 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Diversity vs Demand, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["215.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1c06424e-b541-46ef-ac64-c89327a4293e', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 6, 'paragraph', 'Practical example', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["215.2","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('395f1950-9dbb-47f5-9d63-729e17faa5b7', 'e0b1e379-a058-4bf9-970c-225a755f9a07', 7, 'paragraph', 'Common mistakes', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["215.2","90.1"]}'::jsonb);
