INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9e80654d-67f0-491f-b2c1-240cd055faff', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 4, 'paragraph', 'Key concepts', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["220.82","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d298a805-b247-4adf-a1a5-d7a7f3da2dc9', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 220.82 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Dwelling Optional Method, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 220.82 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Dwelling Optional Method, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["220.82","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1df093c3-ba14-4f2e-bd34-19fe662a0691', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 6, 'paragraph', 'Practical example', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["220.82","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fbce982e-b765-4eb0-88b8-0f4827f4c098', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 7, 'paragraph', 'Common mistakes', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["220.82","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6d124ec7-abd8-431e-ae16-3926e9a118e1', 'e4a8125f-68c4-4d24-b811-6de74f9aa85b', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Dwelling Optional Method inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 220.82. The best strategy is to underline the operating condition, match it to NEC 220.82, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Dwelling Optional Method inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 220.82. The best strategy is to underline the operating condition, match it to NEC 220.82, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["220.82","220.40"]}'::jsonb);
