INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a8a76ea1-275c-4485-8905-f742b4b63044', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 1, 'paragraph', 'Learning objective', 'Use Commercial Demand Sizing to calculate commercial loads, apply multiple methods, verify answers. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Commercial Demand Sizing to calculate commercial loads, apply multiple methods, verify answers. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["220.44","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3596a358-59e2-46b8-830f-c39d732b45da', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 2, 'paragraph', 'Why this matters', 'Commercial Demand Sizing shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Commercial Demand Sizing shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["220.44","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('21f9e27f-1660-4041-88bd-d7fdc3371cff', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 3, 'paragraph', 'Core explanation', 'Commercial Demand Sizing is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Commercial Demand Sizing is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["220.44","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ce00605f-d0be-442d-bc33-2ec822987ff4', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 4, 'paragraph', 'Key concepts', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["220.44","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4631305d-1f41-4d7f-9cd9-ab9c9c3a0f09', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 220.44 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Commercial Demand Sizing, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 220.44 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Commercial Demand Sizing, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["220.44","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a8a49828-cf65-4e48-913f-41e0554596bb', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 6, 'paragraph', 'Practical example', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["220.44","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5008b089-592d-4a40-ae22-6c53da205c80', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 7, 'paragraph', 'Common mistakes', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["220.44","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('df8c3308-ce24-4fcc-b751-0f0caa9db589', '962e1229-3cb3-4e52-853b-e565e4aaf88a', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Commercial Demand Sizing inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 220.44 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 220.44, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Commercial Demand Sizing inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 220.44 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 220.44, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["220.44","220.40"]}'::jsonb);
