INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ffbf96b6-3070-4d50-9941-d08aecf936cb', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 1, 'paragraph', 'Learning objective', 'Use Special Load Types to handle motor loads, handle heating/cooling, combine correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Special Load Types to handle motor loads, handle heating/cooling, combine correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["220.50","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3ca57ed4-d44a-42ac-b6fa-1f771d37eb25', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 2, 'paragraph', 'Why this matters', 'Special Load Types shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Special Load Types shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["220.50","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('cf677c4f-5376-4579-bbba-9ea2bd5cc864', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 3, 'paragraph', 'Core explanation', 'Special Load Types is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Special Load Types is a calculation topic, so the safest approach is to write the governing rule, list the known values, and solve in the same order every time. Most wrong answers come from using the wrong starting value or applying the correct factor at the wrong step. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["220.50","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c23205fc-b073-44d5-8603-62212d9559d2', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 4, 'paragraph', 'Key concepts', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Separate base load, demand factors, adjustment factors, correction factors, and final equipment selection. Exams reward candidates who keep those steps distinct instead of blending them into one unsupported number. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["220.50","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2c9d7c20-8b2b-4770-bd0f-e092f6e8babc', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 220.50 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Special Load Types, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 220.50 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Special Load Types, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["220.50","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4fb54f58-0ebb-4232-b6c7-a9126a75dbc9', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 6, 'paragraph', 'Practical example', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'In practice, these calculations influence conductor sizing, overcurrent protection, feeder design, service selection, and equipment layout. A field-ready calculation is repeatable and clear enough that another electrician can audit it from your notes. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["220.50","220.40"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fd2484d1-b331-49f3-85b2-28964e6954ec', '9893a3b5-6c9b-4adb-bb79-5170fb6cf62e', 7, 'paragraph', 'Common mistakes', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', 'The most common miss is using table values out of context or skipping a required multiplier such as the continuous-load adder. Another is choosing the final conductor or device before the code calculation is actually complete. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["220.50","220.40"]}'::jsonb);
