INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('458a93e9-4106-424d-bd6d-7f62a87ca3ba', 'ca30e537-4d3b-45ec-983d-1632781f5375', 1, 'paragraph', 'Learning objective', 'Use Hazardous Location Basics to understand classification, know protection methods, select equipment. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Hazardous Location Basics to understand classification, know protection methods, select equipment. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["500.5","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fe2c3371-d083-4d06-a001-42a73d3aec5f', 'ca30e537-4d3b-45ec-983d-1632781f5375', 2, 'paragraph', 'Why this matters', 'Hazardous Location Basics shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Hazardous Location Basics shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["500.5","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ec36f51b-0758-4b77-ad9d-1f36afa6c674', 'ca30e537-4d3b-45ec-983d-1632781f5375', 3, 'paragraph', 'Core explanation', 'Hazardous Location Basics is about controlling exposure before a person gets near energized parts. The safe sequence matters: identify the hazard, establish an electrically safe work condition when required, and confirm that protective measures actually match the task. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Hazardous Location Basics is about controlling exposure before a person gets near energized parts. The safe sequence matters: identify the hazard, establish an electrically safe work condition when required, and confirm that protective measures actually match the task. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["500.5","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('16969cbe-5bc3-418d-8cfd-faaa0272a582', 'ca30e537-4d3b-45ec-983d-1632781f5375', 4, 'paragraph', 'Key concepts', 'Think in layers: shock protection, arc-flash protection, equipment condition, and work practice. When one layer is weak, the rest of the plan has to compensate or the task should stop until conditions are corrected. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Think in layers: shock protection, arc-flash protection, equipment condition, and work practice. When one layer is weak, the rest of the plan has to compensate or the task should stop until conditions are corrected. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["500.5","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9259c161-4659-487a-838b-4c47fa9eac2f', 'ca30e537-4d3b-45ec-983d-1632781f5375', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 500.5 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Hazardous Location Basics, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 500.5 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Hazardous Location Basics, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["500.5","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ce00d8a8-6b2a-42ba-99f0-ea422aa79819', 'ca30e537-4d3b-45ec-983d-1632781f5375', 6, 'paragraph', 'Practical example', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["500.5","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('93a1489b-059b-41f2-918b-8fb9fdcc5555', 'ca30e537-4d3b-45ec-983d-1632781f5375', 7, 'paragraph', 'Common mistakes', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. When you review misses, look for the first step where the condition or reference was ignored.', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["500.5","90.3"]}'::jsonb);
