INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6408c02c-0bd4-4673-9806-e4bb17ddbb42', '678c48d5-ca88-4097-9dcf-34629e8e2d7c', 1, 'paragraph', 'Learning objective', 'Use Class I Locations to know class i rules, select wiring methods, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Class I Locations to know class i rules, select wiring methods, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["501.10","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5ad69e63-8166-4962-b90c-14508a6d695d', '678c48d5-ca88-4097-9dcf-34629e8e2d7c', 2, 'paragraph', 'Why this matters', 'Class I Locations shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Class I Locations shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["501.10","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ddf44b62-574d-455c-bd0e-55f4a18715b2', '678c48d5-ca88-4097-9dcf-34629e8e2d7c', 3, 'paragraph', 'Core explanation', 'Class I Locations is about controlling exposure before a person gets near energized parts. The safe sequence matters: identify the hazard, establish an electrically safe work condition when required, and confirm that protective measures actually match the task. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'Class I Locations is about controlling exposure before a person gets near energized parts. The safe sequence matters: identify the hazard, establish an electrically safe work condition when required, and confirm that protective measures actually match the task. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["501.10","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('54a23eb1-4e69-4a1d-8034-5bdeea36bb76', '678c48d5-ca88-4097-9dcf-34629e8e2d7c', 4, 'paragraph', 'Key concepts', 'Think in layers: shock protection, arc-flash protection, equipment condition, and work practice. When one layer is weak, the rest of the plan has to compensate or the task should stop until conditions are corrected. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Think in layers: shock protection, arc-flash protection, equipment condition, and work practice. When one layer is weak, the rest of the plan has to compensate or the task should stop until conditions are corrected. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["501.10","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c5673f02-7f7d-4b79-8ffa-d15c175a1270', '678c48d5-ca88-4097-9dcf-34629e8e2d7c', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 501.10 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Class I Locations, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 501.10 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Class I Locations, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["501.10","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0ab58f9a-36c1-439d-8e4a-f7d3c973be84', '678c48d5-ca88-4097-9dcf-34629e8e2d7c', 6, 'paragraph', 'Practical example', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["501.10","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('98c40a76-dc77-4f26-9a3f-bea1974a2291', '678c48d5-ca88-4097-9dcf-34629e8e2d7c', 7, 'paragraph', 'Common mistakes', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["501.10","90.3"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5cb46bd6-8bed-43ca-af6a-d993e47f2f86', '678c48d5-ca88-4097-9dcf-34629e8e2d7c', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Class I Locations inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 501.10. The best strategy is to underline the operating condition, match it to NEC 501.10, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Class I Locations inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 501.10. The best strategy is to underline the operating condition, match it to NEC 501.10, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["501.10","90.3"]}'::jsonb);
