INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ea265ba6-85fb-468e-aaf8-d8441c2b87c3', '6c0b621d-b699-46ab-9b97-0118771a99b5', 4, 'paragraph', 'Key concepts', 'Think in layers: shock protection, arc-flash protection, equipment condition, and work practice. When one layer is weak, the rest of the plan has to compensate or the task should stop until conditions are corrected. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Think in layers: shock protection, arc-flash protection, equipment condition, and work practice. When one layer is weak, the rest of the plan has to compensate or the task should stop until conditions are corrected. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["503.10","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bc3cbe9a-7e95-4aec-aa36-1671f4ecaf21', '6c0b621d-b699-46ab-9b97-0118771a99b5', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 503.10 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Class III and Zone Systems, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 503.10 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Class III and Zone Systems, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["503.10","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e59b0b97-7059-4c28-bc10-9394ae0b2335', '6c0b621d-b699-46ab-9b97-0118771a99b5', 6, 'paragraph', 'Practical example', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'A real crew uses this topic during job briefing, lockout, absence-of-voltage verification, PPE selection, and re-energization planning. The best field habit is to slow the task down enough that every protective step is deliberate and documented. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["503.10","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('edb741c8-9069-4589-b622-367bdca705aa', '6c0b621d-b699-46ab-9b97-0118771a99b5', 7, 'paragraph', 'Common mistakes', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'Candidates often memorize terms but forget the order of operations. Trouble starts when someone assumes a disconnect is sufficient proof of safety, skips testing, or treats PPE as a substitute for de-energizing when the work could have been made safe first. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["503.10","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f321f554-b71a-4382-b6a4-b38ea894cb08', '6c0b621d-b699-46ab-9b97-0118771a99b5', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Class III and Zone Systems inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 503.10. The best strategy is to underline the operating condition, match it to NEC 503.10, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Class III and Zone Systems inside a short scenario instead of naming the rule directly. Most misses happen when the candidate answers from habit instead of identifying the exact condition that activates NEC 503.10. The best strategy is to underline the operating condition, match it to NEC 503.10, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["503.10","90.1"]}'::jsonb);
