INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('be16cdad-5fbe-45a9-917b-1286c767dac1', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 1, 'paragraph', 'Learning objective', 'Use Emergency Systems Article 700 to know emergency rules, understand requirements, design systems. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Emergency Systems Article 700 to know emergency rules, understand requirements, design systems. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 700","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f7001d77-4c62-408e-8681-d9036f109b9e', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 2, 'paragraph', 'Why this matters', 'Emergency Systems Article 700 shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Emergency Systems Article 700 shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 700","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5c2eedad-d83e-41ff-8c70-787707a7c254', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 3, 'paragraph', 'Core explanation', 'Emergency Systems Article 700 combines code knowledge with practical field judgment. A strong answer shows that you understand both the purpose of the rule and the installation decision that follows from it. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Emergency Systems Article 700 combines code knowledge with practical field judgment. A strong answer shows that you understand both the purpose of the rule and the installation decision that follows from it. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["Article 700","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('7fe96278-9070-4718-8b9f-9322402dfab1', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 4, 'paragraph', 'Key concepts', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["Article 700","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2a9c728a-6b8b-475c-bed1-e37c79aa4dc4', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 700 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Emergency Systems Article 700, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 700 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Emergency Systems Article 700, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 700","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5b98b74c-161f-42bd-b59b-df073fc33fac', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 6, 'paragraph', 'Practical example', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["Article 700","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e0210e6d-dd02-4d5a-b28a-ca40031101cc', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 7, 'paragraph', 'Common mistakes', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. When you review misses, look for the first step where the condition or reference was ignored.', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["Article 700","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ee0173ee-3847-46cf-9b71-2cf63d7963b7', 'dcb92cbb-ce6e-4fd3-967b-f7c0f8edb930', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Emergency Systems Article 700 inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 700 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 700, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Emergency Systems Article 700 inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 700 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 700, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 700","90.1"]}'::jsonb);
