INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('06db5d09-f37f-422d-96cc-e0ea92ee4f46', 'e144f9c6-8306-4df4-8c70-90e279113206', 6, 'paragraph', 'Practical example', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["Article 701","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1a586adb-9cdf-42e9-8804-9f2678186b86', 'e144f9c6-8306-4df4-8c70-90e279113206', 7, 'paragraph', 'Common mistakes', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["Article 701","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('2d6179bd-e5f6-44d7-bd1c-d9c5fb26f994', 'e144f9c6-8306-4df4-8c70-90e279113206', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Legally Required Standby Article 701 inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 701. The best strategy is to underline the operating condition, match it to NEC Article 701, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Legally Required Standby Article 701 inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 701. The best strategy is to underline the operating condition, match it to NEC Article 701, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 701","90.1"]}'::jsonb);
