INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d45b4f08-deb3-4d37-85df-977e4e2f7c0d', '8da4fe60-7c97-4779-b751-2ba7c3dde638', 1, 'paragraph', 'Learning objective', 'Use Optional Standby Article 702 to know optional rules, understand requirements, design systems. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Optional Standby Article 702 to know optional rules, understand requirements, design systems. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 702","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('87ff6625-8b3c-4d47-8e40-95a3e2ecff0c', '8da4fe60-7c97-4779-b751-2ba7c3dde638', 2, 'paragraph', 'Why this matters', 'Optional Standby Article 702 shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Optional Standby Article 702 shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 702","90.1"]}'::jsonb);
