INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d7dc3a33-d955-4e8b-af9f-5766388057e0', 'ff910cf6-5e12-45f7-982b-be755b4811a8', 1, 'paragraph', 'Learning objective', 'Use Healthcare Facilities Article 517 to know healthcare rules, understand critical areas, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Healthcare Facilities Article 517 to know healthcare rules, understand critical areas, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 517","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6e371358-58c4-4e81-93aa-fd156ec82efd', 'ff910cf6-5e12-45f7-982b-be755b4811a8', 2, 'paragraph', 'Why this matters', 'Healthcare Facilities Article 517 shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Healthcare Facilities Article 517 shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 517","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('22db2c48-a058-42c9-8012-3c631110d867', 'ff910cf6-5e12-45f7-982b-be755b4811a8', 3, 'paragraph', 'Core explanation', 'Healthcare Facilities Article 517 explains the electrical relationship that a supervisory and design-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Healthcare Facilities Article 517 explains the electrical relationship that a supervisory and design-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["Article 517","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0993d2d1-a380-4bea-94fa-99ab10f3435e', 'ff910cf6-5e12-45f7-982b-be755b4811a8', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The misconception to avoid is treating healthcare facilities article 517 as vocabulary instead of as an installation or design decision.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The misconception to avoid is treating healthcare facilities article 517 as vocabulary instead of as an installation or design decision.', '{"necReferences":["Article 517","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('811ff336-b9b8-4fad-a664-838383d58783', 'ff910cf6-5e12-45f7-982b-be755b4811a8', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 517 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Healthcare Facilities Article 517, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 517 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Healthcare Facilities Article 517, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 517","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9c35fd68-45ea-468e-8c6b-b697d671851c', 'ff910cf6-5e12-45f7-982b-be755b4811a8', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["Article 517","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a8e9a7af-bb71-48f9-a0ef-016faaa23fff', 'ff910cf6-5e12-45f7-982b-be755b4811a8', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["Article 517","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0579d23f-fa9d-4626-b3da-ba26d85dd077', 'ff910cf6-5e12-45f7-982b-be755b4811a8', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Healthcare Facilities Article 517 inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 517. The best strategy is to underline the operating condition, match it to NEC Article 517, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Healthcare Facilities Article 517 inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 517. The best strategy is to underline the operating condition, match it to NEC Article 517, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 517","90.1"]}'::jsonb);
