INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('41899ffb-6d1d-45ed-b23b-520312641342', 'c32745d3-6255-401e-aa13-fc55e2737ac9', 2, 'paragraph', 'Why this matters', 'Patient Care Areas shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Patient Care Areas shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["517.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('92de5e57-e753-45a0-a75f-f580f703d464', 'c32745d3-6255-401e-aa13-fc55e2737ac9', 3, 'paragraph', 'Core explanation', 'Patient Care Areas belongs to a specialty area where the location or system condition changes the ordinary rule. The safest exam approach is to identify the hazardous, special-occupancy, or special-equipment condition first and then apply the modified requirement. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Patient Care Areas belongs to a specialty area where the location or system condition changes the ordinary rule. The safest exam approach is to identify the hazardous, special-occupancy, or special-equipment condition first and then apply the modified requirement. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["517.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('52d0e9c0-db37-4af7-939b-4c01ec91c449', 'c32745d3-6255-401e-aa13-fc55e2737ac9', 4, 'paragraph', 'Key concepts', 'Watch for words that change the environment: classified location, dust, vapor, zone, emergency system, health care, or special occupancy. Those signals tell you when the code is adding restrictions that do not appear in ordinary installations. The misconception to avoid is treating patient care areas as vocabulary instead of as an installation or design decision.', 'Watch for words that change the environment: classified location, dust, vapor, zone, emergency system, health care, or special occupancy. Those signals tell you when the code is adding restrictions that do not appear in ordinary installations. The misconception to avoid is treating patient care areas as vocabulary instead of as an installation or design decision.', '{"necReferences":["517.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('71dfc856-902d-44e2-bd04-1a9617125b85', 'c32745d3-6255-401e-aa13-fc55e2737ac9', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 517.20 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Patient Care Areas, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 517.20 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Patient Care Areas, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["517.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f1ccf66a-082a-4a62-ad7a-5c1fa8a99a2d', 'c32745d3-6255-401e-aa13-fc55e2737ac9', 6, 'paragraph', 'Practical example', 'Field decisions in these spaces are stricter because the consequences of ignition, interruption, or equipment misuse are higher. Correct work depends on choosing the right equipment listing and wiring method for the exact location class or system purpose. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'Field decisions in these spaces are stricter because the consequences of ignition, interruption, or equipment misuse are higher. Correct work depends on choosing the right equipment listing and wiring method for the exact location class or system purpose. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["517.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('595a35f3-a542-4748-8529-2728e6028ddd', 'c32745d3-6255-401e-aa13-fc55e2737ac9', 7, 'paragraph', 'Common mistakes', 'A common miss is answering from the general rule and forgetting that the special chapter overrides it. Another is selecting equipment that would be acceptable in a normal space but is not listed or protected for the special condition described. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'A common miss is answering from the general rule and forgetting that the special chapter overrides it. Another is selecting equipment that would be acceptable in a normal space but is not listed or protected for the special condition described. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["517.20","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('498bd34a-89f0-4cd2-8bc0-4cd7f893b4c7', 'c32745d3-6255-401e-aa13-fc55e2737ac9', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Patient Care Areas inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 517.20. The best strategy is to underline the operating condition, match it to NEC 517.20, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Patient Care Areas inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC 517.20. The best strategy is to underline the operating condition, match it to NEC 517.20, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["517.20","90.1"]}'::jsonb);
