INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('45e5b989-c18d-4cf7-87d8-08f8334496c7', '8163afb7-9a9c-4470-ba54-fa50e991c0c9', 1, 'paragraph', 'Learning objective', 'Use Assembly and Entertainment to know assembly rules, understand theater rules, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Assembly and Entertainment to know assembly rules, understand theater rules, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 518","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ef15b8ec-302d-41c0-9365-16c25ec32284', '8163afb7-9a9c-4470-ba54-fa50e991c0c9', 2, 'paragraph', 'Why this matters', 'Assembly and Entertainment shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Assembly and Entertainment shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 518","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('fce9417e-a692-4f63-b221-8c016df8f2ed', '8163afb7-9a9c-4470-ba54-fa50e991c0c9', 3, 'paragraph', 'Core explanation', 'Assembly and Entertainment belongs to a specialty area where the location or system condition changes the ordinary rule. The safest exam approach is to identify the hazardous, special-occupancy, or special-equipment condition first and then apply the modified requirement. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Assembly and Entertainment belongs to a specialty area where the location or system condition changes the ordinary rule. The safest exam approach is to identify the hazardous, special-occupancy, or special-equipment condition first and then apply the modified requirement. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["Article 518","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5d7153b8-48ea-4b4d-9084-ec7fd3720923', '8163afb7-9a9c-4470-ba54-fa50e991c0c9', 4, 'paragraph', 'Key concepts', 'Watch for words that change the environment: classified location, dust, vapor, zone, emergency system, health care, or special occupancy. Those signals tell you when the code is adding restrictions that do not appear in ordinary installations. The misconception to avoid is treating assembly and entertainment as vocabulary instead of as an installation or design decision.', 'Watch for words that change the environment: classified location, dust, vapor, zone, emergency system, health care, or special occupancy. Those signals tell you when the code is adding restrictions that do not appear in ordinary installations. The misconception to avoid is treating assembly and entertainment as vocabulary instead of as an installation or design decision.', '{"necReferences":["Article 518","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('61b7ad79-be80-41b7-a09a-d5982f0d5493', '8163afb7-9a9c-4470-ba54-fa50e991c0c9', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 518 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Assembly and Entertainment, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 518 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Assembly and Entertainment, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 518","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4677230e-5548-462e-8de0-3dfd9b415522', '8163afb7-9a9c-4470-ba54-fa50e991c0c9', 6, 'paragraph', 'Practical example', 'Field decisions in these spaces are stricter because the consequences of ignition, interruption, or equipment misuse are higher. Correct work depends on choosing the right equipment listing and wiring method for the exact location class or system purpose. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'Field decisions in these spaces are stricter because the consequences of ignition, interruption, or equipment misuse are higher. Correct work depends on choosing the right equipment listing and wiring method for the exact location class or system purpose. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["Article 518","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5a8ec923-b5c7-46f1-ba20-b8466470539b', '8163afb7-9a9c-4470-ba54-fa50e991c0c9', 7, 'paragraph', 'Common mistakes', 'A common miss is answering from the general rule and forgetting that the special chapter overrides it. Another is selecting equipment that would be acceptable in a normal space but is not listed or protected for the special condition described. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'A common miss is answering from the general rule and forgetting that the special chapter overrides it. Another is selecting equipment that would be acceptable in a normal space but is not listed or protected for the special condition described. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["Article 518","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('888e6a44-66f4-4b55-be02-62acf3998c15', '8163afb7-9a9c-4470-ba54-fa50e991c0c9', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Assembly and Entertainment inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 518. The best strategy is to underline the operating condition, match it to NEC Article 518, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Assembly and Entertainment inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 518. The best strategy is to underline the operating condition, match it to NEC Article 518, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 518","90.1"]}'::jsonb);
