INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9a6cde0b-732a-47d7-9c57-d19d2bb82bff', '172dda62-cf11-4a42-9ba2-591ab6ea3fb7', 1, 'paragraph', 'Learning objective', 'Use Motion Picture and TV to know production rules, understand equipment, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Motion Picture and TV to know production rules, understand equipment, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["530.10","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('170feff0-c95e-439d-a713-a936dbc2b420', '172dda62-cf11-4a42-9ba2-591ab6ea3fb7', 2, 'paragraph', 'Why this matters', 'Motion Picture and TV shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Motion Picture and TV shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["530.10","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('26ee1940-2546-46ac-87d0-198c5aa1ab77', '172dda62-cf11-4a42-9ba2-591ab6ea3fb7', 3, 'paragraph', 'Core explanation', 'Motion Picture and TV belongs to a specialty area where the location or system condition changes the ordinary rule. The safest exam approach is to identify the hazardous, special-occupancy, or special-equipment condition first and then apply the modified requirement. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Motion Picture and TV belongs to a specialty area where the location or system condition changes the ordinary rule. The safest exam approach is to identify the hazardous, special-occupancy, or special-equipment condition first and then apply the modified requirement. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["530.10","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('87638fd3-72f6-403f-b32d-222442a7a66f', '172dda62-cf11-4a42-9ba2-591ab6ea3fb7', 4, 'paragraph', 'Key concepts', 'Watch for words that change the environment: classified location, dust, vapor, zone, emergency system, health care, or special occupancy. Those signals tell you when the code is adding restrictions that do not appear in ordinary installations. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Watch for words that change the environment: classified location, dust, vapor, zone, emergency system, health care, or special occupancy. Those signals tell you when the code is adding restrictions that do not appear in ordinary installations. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["530.10","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a469dcc9-7603-48e9-b6da-99d9da532bbc', '172dda62-cf11-4a42-9ba2-591ab6ea3fb7', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 530.10 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Motion Picture and TV, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 530.10 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Motion Picture and TV, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["530.10","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c33fd46a-7c61-44bd-a2e6-33344ad2d1b3', '172dda62-cf11-4a42-9ba2-591ab6ea3fb7', 6, 'paragraph', 'Practical example', 'Field decisions in these spaces are stricter because the consequences of ignition, interruption, or equipment misuse are higher. Correct work depends on choosing the right equipment listing and wiring method for the exact location class or system purpose. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'Field decisions in these spaces are stricter because the consequences of ignition, interruption, or equipment misuse are higher. Correct work depends on choosing the right equipment listing and wiring method for the exact location class or system purpose. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["530.10","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('d5d25b3d-4dc9-4489-9256-5240f03c7b9f', '172dda62-cf11-4a42-9ba2-591ab6ea3fb7', 7, 'paragraph', 'Common mistakes', 'A common miss is answering from the general rule and forgetting that the special chapter overrides it. Another is selecting equipment that would be acceptable in a normal space but is not listed or protected for the special condition described. When you review misses, look for the first step where the condition or reference was ignored.', 'A common miss is answering from the general rule and forgetting that the special chapter overrides it. Another is selecting equipment that would be acceptable in a normal space but is not listed or protected for the special condition described. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["530.10","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f662afd3-d92e-4eea-a22b-6f61a00c080a', '172dda62-cf11-4a42-9ba2-591ab6ea3fb7', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Motion Picture and TV inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 530.10 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 530.10, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Motion Picture and TV inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC 530.10 treats as decisive. The best strategy is to underline the operating condition, match it to NEC 530.10, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["530.10","90.1"]}'::jsonb);
