INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6416543c-6f7f-42ff-ae16-df7f03068717', '07539d11-1ae8-4f06-b966-65ab2121c2e2', 4, 'paragraph', 'Key concepts', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The misconception to avoid is treating pool and spa requirements as vocabulary instead of as an installation or design decision.', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The misconception to avoid is treating pool and spa requirements as vocabulary instead of as an installation or design decision.', '{"necReferences":["Article 680","90.1"]}'::jsonb);
