INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ac098843-d0ce-4cd2-98b0-d6d7de2c0cd8', '07539d11-1ae8-4f06-b966-65ab2121c2e2', 6, 'paragraph', 'Practical example', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["Article 680","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6b446dfd-d4d6-4ed2-88b2-dd61eb7e1fcb', '07539d11-1ae8-4f06-b966-65ab2121c2e2', 7, 'paragraph', 'Common mistakes', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["Article 680","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f98f8678-1ddc-4755-b353-af60c5fb80d9', '07539d11-1ae8-4f06-b966-65ab2121c2e2', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Pool and Spa Requirements inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 680. The best strategy is to underline the operating condition, match it to NEC Article 680, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Pool and Spa Requirements inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 680. The best strategy is to underline the operating condition, match it to NEC Article 680, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 680","90.1"]}'::jsonb);
