INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('51483270-ae98-4df1-94c8-fa27426b9e04', 'be7e0529-3767-462c-af64-31fb0da382f9', 1, 'paragraph', 'Learning objective', 'Use Pool Bonding and Grounding to know bonding rules, calculate sizes, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Pool Bonding and Grounding to know bonding rules, calculate sizes, apply correctly. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["680.26","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('bd11bf01-6b4e-42b7-85d3-47ad0d2cdd94', 'be7e0529-3767-462c-af64-31fb0da382f9', 2, 'paragraph', 'Why this matters', 'Pool Bonding and Grounding shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Pool Bonding and Grounding shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["680.26","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5fec51b4-7209-40e3-bde1-50841e7443ec', 'be7e0529-3767-462c-af64-31fb0da382f9', 3, 'paragraph', 'Core explanation', 'Pool Bonding and Grounding deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Pool Bonding and Grounding deals with fault-current paths, bonding continuity, and the distinction between grounding and bonding. The exam expects you to know which connection stabilizes the system, which connection clears a fault, and where each one belongs. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["680.26","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('713e0937-93fd-4d41-841c-47c0ed90d5e1', 'be7e0529-3767-462c-af64-31fb0da382f9', 4, 'paragraph', 'Key concepts', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The misconception to avoid is treating pool bonding and grounding as vocabulary instead of as an installation or design decision.', 'Track the intentional path for normal current and the low-impedance path for fault current separately. When those ideas get blurred together, grounding questions become much harder than they need to be. The misconception to avoid is treating pool bonding and grounding as vocabulary instead of as an installation or design decision.', '{"necReferences":["680.26","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('41f8e2f6-9936-47bf-9ebd-094af3b4bc6e', 'be7e0529-3767-462c-af64-31fb0da382f9', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 680.26 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Pool Bonding and Grounding, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 680.26 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Pool Bonding and Grounding, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["680.26","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('acbe78e2-1a91-483f-82e7-5128d35bc88f', 'be7e0529-3767-462c-af64-31fb0da382f9', 6, 'paragraph', 'Practical example', 'This topic matters when you connect service equipment, feeders, separate buildings, electrodes, and equipment grounding conductors. Good grounding work is deliberate, continuous, and sized to perform under fault conditions rather than by appearance alone. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'This topic matters when you connect service equipment, feeders, separate buildings, electrodes, and equipment grounding conductors. Good grounding work is deliberate, continuous, and sized to perform under fault conditions rather than by appearance alone. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["680.26","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('37379d03-09d2-4208-b95d-b70c2d1cc320', 'be7e0529-3767-462c-af64-31fb0da382f9', 7, 'paragraph', 'Common mistakes', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'A frequent error is bonding where isolation is required or isolating where bonding is required. Another is choosing a grounding electrode conductor or equipment grounding conductor from the wrong table. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["680.26","90.1"]}'::jsonb);
