INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('02718f5e-daac-4c99-9acf-0edfebbb77f6', '8a5dde75-948e-4d62-9b10-3bafb57ac572', 1, 'paragraph', 'Learning objective', 'Use Solar PV Systems Article 690 to know pv rules, understand components, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Solar PV Systems Article 690 to know pv rules, understand components, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 690","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('81b55e04-aeba-4598-beb9-6000fe96cc93', '8a5dde75-948e-4d62-9b10-3bafb57ac572', 2, 'paragraph', 'Why this matters', 'Solar PV Systems Article 690 shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Solar PV Systems Article 690 shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Candidates usually perform better here when they can explain the decision, not just repeat the lesson title. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 690","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('928c3fd3-4eb6-49bd-a990-de9107d2cb36', '8a5dde75-948e-4d62-9b10-3bafb57ac572', 3, 'paragraph', 'Core explanation', 'Solar PV Systems Article 690 explains the electrical relationship that a supervisory and design-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Solar PV Systems Article 690 explains the electrical relationship that a supervisory and design-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["Article 690","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('71e67b7c-ac63-4889-867b-c770ce712aad', '8a5dde75-948e-4d62-9b10-3bafb57ac572', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["Article 690","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b0f2bcf9-445e-40e3-b2a8-8fbf807a23c9', '8a5dde75-948e-4d62-9b10-3bafb57ac572', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 690 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Solar PV Systems Article 690, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 690 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Solar PV Systems Article 690, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 690","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('f06926e3-f63a-43af-9ec5-bcb781902e0b', '8a5dde75-948e-4d62-9b10-3bafb57ac572', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["Article 690","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('1e76b93b-7c0b-487d-a07b-2789de59f591', '8a5dde75-948e-4d62-9b10-3bafb57ac572', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["Article 690","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('561b831e-40de-4664-a8fe-7275af355808', '8a5dde75-948e-4d62-9b10-3bafb57ac572', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Solar PV Systems Article 690 inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 690 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 690, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Solar PV Systems Article 690 inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 690 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 690, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 690","90.1"]}'::jsonb);
