INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3d25560d-0214-4813-ba75-47c5fd38a961', 'd319a639-35f1-47e1-8422-46b35054d8cd', 1, 'paragraph', 'Learning objective', 'Use Energy Storage Article 706 to know storage rules, understand systems, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use Energy Storage Article 706 to know storage rules, understand systems, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["Article 706","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4ca27ea2-6579-486b-8b6b-94ce5daf42af', 'd319a639-35f1-47e1-8422-46b35054d8cd', 2, 'paragraph', 'Why this matters', 'Energy Storage Article 706 shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'Energy Storage Article 706 shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. Licensing questions lean on this rule because it separates memorized phrases from code-based judgment. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 706","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5ef90201-88a6-401d-af55-3f92d696adc3', 'd319a639-35f1-47e1-8422-46b35054d8cd', 3, 'paragraph', 'Core explanation', 'Energy Storage Article 706 explains the electrical relationship that a supervisory and design-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', 'Energy Storage Article 706 explains the electrical relationship that a supervisory and design-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. This is the kind of issue that turns into a failed inspection or troubleshooting delay when the first decision is made too fast.', '{"necReferences":["Article 706","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e761a521-c83d-4daf-a964-8b5d6520c1d4', 'd319a639-35f1-47e1-8422-46b35054d8cd', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The misconception to avoid is treating energy storage article 706 as vocabulary instead of as an installation or design decision.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The misconception to avoid is treating energy storage article 706 as vocabulary instead of as an installation or design decision.', '{"necReferences":["Article 706","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('3460fb05-18c9-4bc3-820d-b5dd5e58d5c2', 'd319a639-35f1-47e1-8422-46b35054d8cd', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 706 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Energy Storage Article 706, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 706 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For Energy Storage Article 706, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 706","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('9140d709-e558-46f8-be7a-ea1c2a27d1cd', 'd319a639-35f1-47e1-8422-46b35054d8cd', 6, 'paragraph', 'Practical example', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', 'On the job, this concept shows up before you size equipment or troubleshoot a circuit. A clean sketch, a known value, and one checked calculation usually tell you whether the issue is load-related, conductor-related, or device-related. If you can point to the condition, the governing NEC section, and the resulting installation decision, you are usually on the right track.', '{"necReferences":["Article 706","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('22439551-7f67-41ec-ac76-95f30e173b37', 'd319a639-35f1-47e1-8422-46b35054d8cd', 7, 'paragraph', 'Common mistakes', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', 'A common exam mistake is mixing up the quantity you are solving for with the quantity that was already given. Another is skipping units, which can hide whether the answer belongs in amperes, volts, ohms, watts, or volt-amperes. A clean review process asks what changed, what rule controlled, and which answer choice failed to respect that difference.', '{"necReferences":["Article 706","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('5421fc41-a860-44b6-836b-1b80428385e5', 'd319a639-35f1-47e1-8422-46b35054d8cd', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Energy Storage Article 706 inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 706. The best strategy is to underline the operating condition, match it to NEC Article 706, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Energy Storage Article 706 inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 706. The best strategy is to underline the operating condition, match it to NEC Article 706, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 706","90.1"]}'::jsonb);
