INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('74360269-865b-4ee3-b07e-09f4da1f6473', '63306076-1add-42eb-9108-ff00b75b660e', 3, 'paragraph', 'Core explanation', 'Microgrids and Hybrid Systems explains the electrical relationship that a supervisory and design-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', 'Microgrids and Hybrid Systems explains the electrical relationship that a supervisory and design-level candidate is expected to recognize without hesitation. Focus on what changes, what stays constant, and how the quantities affect conductors, devices, or connected loads. Connecting the rule to one concrete field decision makes the topic easier to apply under pressure.', '{"necReferences":["100 (definitions)","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ba70685c-c376-4b00-996b-e1cb5c3a5e50', '63306076-1add-42eb-9108-ff00b75b660e', 4, 'paragraph', 'Key concepts', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Keep the main variables separate in your notes: the source condition, the circuit path, and the resulting load behavior. If the problem includes numbers, write the formula first and then substitute values so the exam does not pull you into mental-math mistakes. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["100 (definitions)","90.1"]}'::jsonb);
