INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('b732f817-3be7-4ad2-8318-5e8e3156e8ad', 'feb48f22-e484-40c1-89a5-b51c2226f321', 4, 'paragraph', 'Key concepts', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The trap here is assuming the first familiar rule applies before checking whether the stated condition changed the answer.', '{"necReferences":["Article 625","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('ffa8b88a-e0ad-40c1-919e-8516ec887231', 'feb48f22-e484-40c1-89a5-b51c2226f321', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 625 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For EV Supply Equipment Article 625, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 625 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For EV Supply Equipment Article 625, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 625","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4e151f3e-3b78-4096-bbf0-0ba138005abb', 'feb48f22-e484-40c1-89a5-b51c2226f321', 6, 'paragraph', 'Practical example', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', 'In practice, this topic affects how electricians plan work, communicate with inspectors, and leave installations that are safe to energize and easy to maintain. Small wording changes in the problem often point to a completely different answer. That same discipline keeps both jobsite decisions and exam answers from drifting into guesswork.', '{"necReferences":["Article 625","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('93aee9e9-e354-4776-9455-239b72a3fd08', 'feb48f22-e484-40c1-89a5-b51c2226f321', 7, 'paragraph', 'Common mistakes', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. When you review misses, look for the first step where the condition or reference was ignored.', 'Candidates often rush to the familiar answer instead of checking the exact condition described. The safer move is to slow down, mark the controlling code phrase, and reject any answer choice that ignores the stated condition. When you review misses, look for the first step where the condition or reference was ignored.', '{"necReferences":["Article 625","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('c9db885f-982b-4b2c-880f-71a307510948', 'feb48f22-e484-40c1-89a5-b51c2226f321', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide EV Supply Equipment Article 625 inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 625 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 625, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide EV Supply Equipment Article 625 inside a short scenario instead of naming the rule directly. On exams, the distractors usually sound familiar because they ignore one condition that NEC Article 625 treats as decisive. The best strategy is to underline the operating condition, match it to NEC Article 625, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 625","90.1"]}'::jsonb);
