INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('142aa3c0-3b47-45db-b627-50347e484605', '1b747f6a-ed59-421f-bc46-dc45638af239', 8, 'paragraph', 'Exam insight', 'Expect the test writer to hide Self-Propelled Vehicles Article 627 inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 627. The best strategy is to underline the operating condition, match it to NEC Article 627, and then eliminate answer choices that ignore the actual condition given in the problem.', 'Expect the test writer to hide Self-Propelled Vehicles Article 627 inside a short scenario instead of naming the rule directly. Expect answer choices that feel almost right but fail because they skip the condition, exception, or code word controlling NEC Article 627. The best strategy is to underline the operating condition, match it to NEC Article 627, and then eliminate answer choices that ignore the actual condition given in the problem.', '{"necReferences":["Article 627","90.1"]}'::jsonb);
