INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('a34f0558-5900-493b-8e75-145cb2dbeac2', 'a26e9e1b-bdea-4f0a-a0eb-bfd5d4cc8241', 1, 'paragraph', 'Learning objective', 'Use EV Charging Protection to know protection rules, size correctly, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', 'Use EV Charging Protection to know protection rules, size correctly, apply requirements. By the end of this lesson, you should be able to explain the rule, connect it to the correct NEC reference, and spot the field decision that the exam is really testing.', '{"necReferences":["625.40","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('e2a9d62a-4892-45fe-81bc-d4c492da7d87', 'a26e9e1b-bdea-4f0a-a0eb-bfd5d4cc8241', 2, 'paragraph', 'Why this matters', 'EV Charging Protection shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', 'EV Charging Protection shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["625.40","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('451e0a0f-23bd-43a8-aa33-e74364f1dd67', 'a26e9e1b-bdea-4f0a-a0eb-bfd5d4cc8241', 3, 'paragraph', 'Core explanation', 'EV Charging Protection combines code knowledge with practical field judgment. A strong answer shows that you understand both the purpose of the rule and the installation decision that follows from it. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', 'EV Charging Protection combines code knowledge with practical field judgment. A strong answer shows that you understand both the purpose of the rule and the installation decision that follows from it. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["625.40","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0dfecad8-6d78-4c22-977f-b803d800814b', 'a26e9e1b-bdea-4f0a-a0eb-bfd5d4cc8241', 4, 'paragraph', 'Key concepts', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Tie every answer back to the condition presented, the controlling requirement, and the practical consequence if the work is done incorrectly. That three-part structure keeps both field and exam reasoning disciplined. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["625.40","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('0ab76af0-3f0a-4e82-98ef-cbc0f771cabc', 'a26e9e1b-bdea-4f0a-a0eb-bfd5d4cc8241', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC 625.40 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For EV Charging Protection, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC 625.40 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For EV Charging Protection, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["625.40","90.1"]}'::jsonb);
