INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('044995d2-8326-464a-8145-05023f5a5a32', '85000636-e917-4b5b-8863-87cf54cd5a10', 2, 'paragraph', 'Why this matters', '2026 NEC Changes and Synthesis shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '2026 NEC Changes and Synthesis shows up in both exam questions and real electrical decisions because it affects safety, compliance, and workmanship. This topic affects how confidently you can defend an answer when the question only gives you one controlling detail. When you understand why the rule exists, it becomes much easier to apply the correct answer in a new scenario instead of memorizing one isolated example.', '{"necReferences":["Article 245","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('8fd68e84-b34c-475b-98c7-57c306c2cd25', '85000636-e917-4b5b-8863-87cf54cd5a10', 3, 'paragraph', 'Core explanation', '2026 NEC Changes and Synthesis teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '2026 NEC Changes and Synthesis teaches how the NEC is organized, how mandatory text is written, and how one rule interacts with another. A strong answer starts by identifying the article, then narrowing to the section, exception, table, or definition that actually controls the situation. A careful electrician would confirm the condition, the applicable reference, and the consequence of getting it wrong before moving on.', '{"necReferences":["Article 245","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('610f70ca-9fdd-4390-a11a-71a6afdede82', '85000636-e917-4b5b-8863-87cf54cd5a10', 4, 'paragraph', 'Key concepts', 'Use code words carefully. Terms such as permitted, required, identified, listed, labeled, and approved are not interchangeable, and exam writers rely on those distinctions when they build distractors. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', 'Use code words carefully. Terms such as permitted, required, identified, listed, labeled, and approved are not interchangeable, and exam writers rely on those distinctions when they build distractors. The fastest way to miss this topic is to skip the definition, table, or exception that narrows the rule to the exact condition in front of you.', '{"necReferences":["Article 245","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('4a688e19-2021-4bf1-a699-ee08f5f9fbf9', '85000636-e917-4b5b-8863-87cf54cd5a10', 5, 'paragraph', 'NEC / code relevance', 'Start this topic with NEC Article 245 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For 2026 NEC Changes and Synthesis, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', 'Start this topic with NEC Article 245 and then confirm any related definitions, exceptions, tables, or companion rules that shape the answer. For 2026 NEC Changes and Synthesis, the code matters because it turns a general electrical idea into a requirement that can be inspected, enforced, and defended on an exam.', '{"necReferences":["Article 245","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('6f4a3516-23d3-4280-97dd-1f1357510602', '85000636-e917-4b5b-8863-87cf54cd5a10', 6, 'paragraph', 'Practical example', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', 'In field practice, this topic matters when a plan reviewer, inspector, foreman, or installer needs the same rule interpreted the same way. Good code use means quoting the controlling section and explaining why it applies to the exact condition in front of you. A short note showing the condition and reference is often enough to keep your reasoning clean under time pressure.', '{"necReferences":["Article 245","90.1"]}'::jsonb);
INSERT INTO lesson_sections (id, lesson_id, sort_order, section_type, heading, body_markdown, body_plaintext, meta_json) VALUES ('25344a55-f47a-4e1c-a7b8-e954cf8dfa83', '85000636-e917-4b5b-8863-87cf54cd5a10', 7, 'paragraph', 'Common mistakes', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', 'A frequent mistake is reading a heading and answering from memory without checking the body text. Another is ignoring Article 100 definitions or forgetting that Chapters 5, 6, and 7 can modify the general rules in Chapters 1 through 4. That pattern is what the test writer is counting on when the wrong answers all seem familiar.', '{"necReferences":["Article 245","90.1"]}'::jsonb);
